import { useState, useEffect, useRef } from 'react'
import { FolderPlus, Plus } from 'lucide-react'
import { toast } from 'sonner'
import { api, type Collection } from '../api/client'
import { cn } from '../lib/utils'

interface AddToCollectionDropdownProps {
  recipeId: number
  onCreateNew: () => void
}

export default function AddToCollectionDropdown({
  recipeId,
  onCreateNew,
}: AddToCollectionDropdownProps) {
  const [isOpen, setIsOpen] = useState(false)
  const [collections, setCollections] = useState<Collection[]>([])
  const [loading, setLoading] = useState(false)
  const [addingTo, setAddingTo] = useState<number | null>(null)
  const dropdownRef = useRef<HTMLDivElement>(null)

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setIsOpen(false)
      }
    }

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [isOpen])

  // Load collections when dropdown opens
  useEffect(() => {
    if (isOpen) {
      loadCollections()
    }
  }, [isOpen])

  const loadCollections = async () => {
    setLoading(true)
    try {
      const data = await api.collections.list()
      setCollections(data)
    } catch (error) {
      console.error('Failed to load collections:', error)
      toast.error('Failed to load collections')
    } finally {
      setLoading(false)
    }
  }

  const handleAddToCollection = async (collectionId: number) => {
    setAddingTo(collectionId)
    try {
      await api.collections.addRecipe(collectionId, recipeId)
      const collection = collections.find((c) => c.id === collectionId)
      toast.success(`Added to ${collection?.name || 'collection'}`)
      setIsOpen(false)
    } catch (error: unknown) {
      if (error instanceof Error && error.message.includes('already')) {
        toast.info('Recipe is already in this collection')
      } else {
        console.error('Failed to add to collection:', error)
        toast.error('Failed to add to collection')
      }
    } finally {
      setAddingTo(null)
    }
  }

  const handleCreateNew = () => {
    setIsOpen(false)
    onCreateNew()
  }

  return (
    <div ref={dropdownRef} className="relative">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="rounded-full bg-black/40 p-2 text-white backdrop-blur-sm transition-colors hover:text-primary"
        title="Add to collection"
      >
        <FolderPlus className="h-5 w-5" />
      </button>

      {isOpen && (
        <div className="absolute right-0 top-full z-50 mt-2 w-56 rounded-lg border border-border bg-card shadow-lg">
          <div className="p-2">
            <h3 className="mb-2 px-2 text-xs font-medium uppercase tracking-wider text-muted-foreground">
              Add to Collection
            </h3>

            {loading ? (
              <div className="px-2 py-4 text-center text-sm text-muted-foreground">
                Loading...
              </div>
            ) : (
              <>
                {collections.length > 0 ? (
                  <div className="max-h-48 overflow-y-auto">
                    {collections.map((collection) => (
                      <button
                        key={collection.id}
                        onClick={() => handleAddToCollection(collection.id)}
                        disabled={addingTo === collection.id}
                        className={cn(
                          'flex w-full items-center gap-2 rounded-md px-2 py-2 text-left text-sm transition-colors',
                          'text-foreground hover:bg-muted disabled:opacity-50'
                        )}
                      >
                        <FolderPlus className="h-4 w-4 text-muted-foreground" />
                        <span className="flex-1 truncate">{collection.name}</span>
                        {addingTo === collection.id && (
                          <span className="text-xs text-muted-foreground">Adding...</span>
                        )}
                      </button>
                    ))}
                  </div>
                ) : (
                  <div className="px-2 py-2 text-sm text-muted-foreground">
                    No collections yet
                  </div>
                )}

                <div className="mt-1 border-t border-border pt-1">
                  <button
                    onClick={handleCreateNew}
                    className="flex w-full items-center gap-2 rounded-md px-2 py-2 text-left text-sm text-primary transition-colors hover:bg-muted"
                  >
                    <Plus className="h-4 w-4" />
                    Create New Collection
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

import { useState, FormEvent } from 'react'
import { api } from '../api/client'

export default function DeviceCodeEntry() {
  const [code, setCode] = useState('')
  const [error, setError] = useState('')
  const [success, setSuccess] = useState(false)
  const [submitting, setSubmitting] = useState(false)

  async function handleSubmit(e: FormEvent) {
    e.preventDefault()
    setError('')
    setSubmitting(true)

    try {
      await api.device.authorize(code)
      setSuccess(true)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Authorization failed')
    } finally {
      setSubmitting(false)
    }
  }

  if (success) {
    return (
      <div className="rounded-md bg-green-50 p-4 text-center text-sm text-green-800 dark:bg-green-900/20 dark:text-green-300">
        Device authorized successfully! The other device should now be connected.
      </div>
    )
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {error && (
        <div role="alert" className="rounded-md bg-red-50 p-3 text-sm text-red-800 dark:bg-red-900/20 dark:text-red-300">
          {error}
        </div>
      )}

      <div>
        <label htmlFor="device-code" className="block text-sm font-medium text-foreground">
          Enter the code shown on the other device
        </label>
        <input
          id="device-code"
          type="text"
          maxLength={6}
          required
          autoComplete="off"
          value={code}
          onChange={(e) => setCode(e.target.value.toUpperCase())}
          placeholder="ABC123"
          className="mt-1 block w-full rounded-md border border-input bg-background px-3 py-2 text-center font-mono text-2xl tracking-widest text-foreground shadow-sm focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
        />
      </div>

      <button
        type="submit"
        disabled={submitting || code.length < 6}
        className="w-full rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground shadow-sm hover:bg-primary/90 disabled:opacity-50"
      >
        {submitting ? 'Authorizing...' : 'Authorize Device'}
      </button>
    </form>
  )
}

import { Component, type ReactNode, type ErrorInfo } from 'react'
import { AlertTriangle, RefreshCw } from 'lucide-react'

interface Props {
  children: ReactNode
  fallback?: ReactNode
}

interface State {
  hasError: boolean
  error: Error | null
  errorInfo: ErrorInfo | null
}

/**
 * Error boundary component that catches JavaScript errors in child components.
 *
 * Displays a user-friendly error UI instead of crashing the entire app.
 * Users can click "Try Again" to reset the error state and remount children.
 *
 * @example
 * <ErrorBoundary>
 *   <App />
 * </ErrorBoundary>
 *
 * // Or with custom fallback
 * <ErrorBoundary fallback={<CustomErrorUI />}>
 *   <App />
 * </ErrorBoundary>
 */
export default class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props)
    this.state = { hasError: false, error: null, errorInfo: null }
  }

  static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error }
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    this.setState({ errorInfo })

    // Log error for debugging
    console.error('ErrorBoundary caught an error:', error, errorInfo)
  }

  handleReset = (): void => {
    this.setState({ hasError: false, error: null, errorInfo: null })
  }

  render(): ReactNode {
    const { hasError, error } = this.state
    const { children, fallback } = this.props

    if (hasError) {
      // Use custom fallback if provided
      if (fallback) {
        return fallback
      }

      // Default error UI
      return (
        <div className="flex min-h-screen flex-col items-center justify-center bg-background p-4">
          <div className="w-full max-w-md rounded-xl border border-border bg-card p-8 text-center shadow-lg">
            {/* Icon */}
            <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-destructive/10">
              <AlertTriangle className="h-8 w-8 text-destructive" />
            </div>

            {/* Title */}
            <h1 className="mb-2 text-xl font-semibold text-foreground">
              Something went wrong
            </h1>

            {/* Description */}
            <p className="mb-6 text-sm text-muted-foreground">
              An unexpected error occurred. This has been logged for debugging.
            </p>

            {/* Error details (development only) */}
            {import.meta.env.DEV && error && (
              <div className="mb-6 rounded-lg bg-muted p-3 text-left">
                <p className="mb-1 text-xs font-medium text-muted-foreground">
                  Error Details
                </p>
                <code className="text-xs text-destructive">
                  {error.name}: {error.message}
                </code>
              </div>
            )}

            {/* Actions */}
            <div className="flex flex-col gap-2">
              <button
                onClick={this.handleReset}
                className="flex w-full items-center justify-center gap-2 rounded-lg bg-primary px-4 py-2.5 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
              >
                <RefreshCw className="h-4 w-4" />
                Try Again
              </button>

              <button
                onClick={() => window.location.reload()}
                className="w-full rounded-lg bg-muted px-4 py-2.5 text-sm font-medium text-muted-foreground transition-colors hover:bg-muted/80 hover:text-foreground"
              >
                Reload Page
              </button>
            </div>
          </div>
        </div>
      )
    }

    return children
  }
}

import { useState, useRef, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { Moon, Sun, Home, Heart, BookOpen, FolderOpen, Settings, LogOut, Users } from 'lucide-react'
import { useProfile } from '../contexts/ProfileContext'

export default function NavHeader() {
  const navigate = useNavigate()
  const { profile, theme, toggleTheme, logout } = useProfile()
  const [dropdownOpen, setDropdownOpen] = useState(false)
  const dropdownRef = useRef<HTMLDivElement>(null)

  const handleLogout = () => {
    logout()
    navigate('/')
  }

  const getInitial = (name: string) => {
    return name.charAt(0).toUpperCase()
  }

  // Close dropdown on outside click
  useEffect(() => {
    if (!dropdownOpen) return
    const handleClick = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setDropdownOpen(false)
      }
    }
    document.addEventListener('mousedown', handleClick)
    return () => document.removeEventListener('mousedown', handleClick)
  }, [dropdownOpen])

  if (!profile) return null

  return (
    <header className="flex items-center justify-between border-b border-border px-4 py-3">
      <button
        onClick={() => navigate('/home')}
        className="text-xl font-medium text-primary hover:opacity-80 transition-opacity"
      >
        Cookie
      </button>

      <div className="flex items-center gap-3">
        {/* Home */}
        <button
          onClick={() => navigate('/home')}
          className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-muted hover:text-primary"
          aria-label="Home"
        >
          <Home className="h-5 w-5" />
        </button>

        {/* All Recipes */}
        <button
          onClick={() => navigate('/all-recipes')}
          className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-muted hover:text-primary"
          aria-label="All recipes"
        >
          <BookOpen className="h-5 w-5" />
        </button>

        {/* Favorites */}
        <button
          onClick={() => navigate('/favorites')}
          className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-muted hover:text-accent"
          aria-label="View favorites"
        >
          <Heart className="h-5 w-5" />
        </button>

        {/* Collections */}
        <button
          onClick={() => navigate('/collections')}
          className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-muted hover:text-primary"
          aria-label="View collections"
        >
          <FolderOpen className="h-5 w-5" />
        </button>

        {/* Theme toggle */}
        <button
          onClick={toggleTheme}
          className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
          aria-label={theme === 'light' ? 'Switch to dark mode' : 'Switch to light mode'}
        >
          {theme === 'light' ? (
            <Moon className="h-5 w-5" />
          ) : (
            <Sun className="h-5 w-5" />
          )}
        </button>

        {/* Settings */}
        <button
          onClick={() => navigate('/settings')}
          className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
          aria-label="Settings"
        >
          <Settings className="h-5 w-5" />
        </button>

        {/* Profile avatar with dropdown */}
        <div className="relative" ref={dropdownRef}>
          <button
            onClick={() => setDropdownOpen(!dropdownOpen)}
            className="flex h-9 w-9 items-center justify-center rounded-full text-sm font-medium text-white"
            style={{ backgroundColor: profile.avatar_color }}
            aria-label={profile.name}
          >
            {getInitial(profile.name)}
          </button>

          {dropdownOpen && (
            <div className="absolute right-0 top-full z-50 mt-1 w-44 rounded-lg border border-border bg-card py-1 shadow-lg">
              <button
                onClick={() => { setDropdownOpen(false); handleLogout() }}
                className="flex w-full items-center gap-2 px-3 py-2 text-sm text-card-foreground hover:bg-muted"
              >
                <Users className="h-4 w-4" />
                Switch profile
              </button>
              <button
                onClick={() => { setDropdownOpen(false); handleLogout() }}
                className="flex w-full items-center gap-2 px-3 py-2 text-sm text-card-foreground hover:bg-muted"
              >
                <LogOut className="h-4 w-4" />
                Log out
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  )
}

import { useState, useCallback } from 'react'
import { Star, Clock, Heart } from 'lucide-react'
import type { Recipe } from '../api/client'
import { cn } from '../lib/utils'
import { formatTime } from '../lib/formatting'

interface RecipeCardProps {
  recipe: Recipe
  isFavorite?: boolean
  onFavoriteToggle?: (recipe: Recipe) => void
  onClick?: (recipe: Recipe) => void
}

export default function RecipeCard({
  recipe,
  isFavorite = false,
  onFavoriteToggle,
  onClick,
}: RecipeCardProps) {
  const imageUrl = recipe.image || recipe.image_url
  const [imgError, setImgError] = useState(false)

  const handleImgError = useCallback(() => {
    setImgError(true)
  }, [])

  const handleFavoriteClick = (e: React.MouseEvent) => {
    e.stopPropagation()
    onFavoriteToggle?.(recipe)
  }

  return (
    <div
      className={cn(
        'group relative overflow-hidden rounded-lg bg-card shadow-sm transition-all hover:shadow-md',
        onClick && 'cursor-pointer'
      )}
      onClick={() => onClick?.(recipe)}
    >
      {/* Image */}
      <div className="relative aspect-[4/3] overflow-hidden bg-muted">
        {imageUrl && !imgError ? (
          <img
            src={imageUrl}
            alt={recipe.title}
            loading="lazy"
            onError={handleImgError}
            className="h-full w-full object-cover transition-transform group-hover:scale-105"
          />
        ) : (
          <div className="flex h-full w-full items-center justify-center bg-muted px-3 text-center text-sm font-medium text-muted-foreground">
            {recipe.title}
          </div>
        )}

        {/* Favorite button */}
        {onFavoriteToggle && (
          <button
            onClick={handleFavoriteClick}
            className={cn(
              'absolute right-2 top-2 rounded-full bg-background/80 p-2 backdrop-blur-sm transition-colors',
              isFavorite
                ? 'text-accent hover:bg-background'
                : 'text-muted-foreground hover:bg-background hover:text-accent'
            )}
            aria-label={isFavorite ? 'Remove from favorites' : 'Add to favorites'}
          >
            <Heart
              className={cn('h-5 w-5', isFavorite && 'fill-current')}
            />
          </button>
        )}

        {/* Remix badge */}
        {recipe.is_remix && (
          <div className="absolute left-2 top-2 rounded-full bg-primary/90 px-2 py-0.5 text-xs text-primary-foreground backdrop-blur-sm">
            Remix
          </div>
        )}
      </div>

      {/* Content */}
      <div className="p-3">
        {/* Title */}
        <h3 className="mb-1 line-clamp-2 text-sm font-medium text-card-foreground">
          {recipe.title}
        </h3>

        {/* Meta */}
        <div className="flex items-center gap-3 text-xs text-muted-foreground">
          {/* Source */}
          <span className="truncate">{recipe.host}</span>

          {/* Time */}
          {recipe.total_time && (
            <span className="flex shrink-0 items-center gap-1">
              <Clock className="h-3 w-3" />
              {formatTime(recipe.total_time)}
            </span>
          )}

          {/* Rating */}
          {recipe.rating && (
            <span className="flex shrink-0 items-center gap-1">
              <Star className="h-3 w-3 fill-star text-star" />
              {recipe.rating.toFixed(1)}
            </span>
          )}
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { X, Sparkles, Loader2, Check } from 'lucide-react'
import { toast } from 'sonner'
import { api, type RecipeDetail } from '../api/client'
import { cn } from '../lib/utils'

interface RemixModalProps {
  recipe: RecipeDetail
  profileId: number
  isOpen: boolean
  onClose: () => void
  onRemixCreated: (recipeId: number) => void
}

export default function RemixModal({
  recipe,
  profileId,
  isOpen,
  onClose,
  onRemixCreated,
}: RemixModalProps) {
  const [suggestions, setSuggestions] = useState<string[]>([])
  const [loadingSuggestions, setLoadingSuggestions] = useState(false)
  const [selectedSuggestions, setSelectedSuggestions] = useState<string[]>([])
  const [customInput, setCustomInput] = useState('')
  const [creating, setCreating] = useState(false)

  // Load suggestions when modal opens
  useEffect(() => {
    if (isOpen) {
      loadSuggestions()
    } else {
      // Reset state when modal closes
      setSuggestions([])
      setSelectedSuggestions([])
      setCustomInput('')
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- loadSuggestions is stable, only re-run when modal opens or recipe changes
  }, [isOpen, recipe.id])

  const loadSuggestions = async () => {
    setLoadingSuggestions(true)
    try {
      const response = await api.ai.remix.getSuggestions(recipe.id)
      setSuggestions(response.suggestions)
    } catch (error) {
      console.error('Failed to load remix suggestions:', error)
      toast.error('Failed to load suggestions')
    } finally {
      setLoadingSuggestions(false)
    }
  }

  const handleSuggestionClick = (suggestion: string) => {
    setSelectedSuggestions((prev) => {
      if (prev.includes(suggestion)) {
        // Remove if already selected
        return prev.filter((s) => s !== suggestion)
      } else {
        // Add to selection (limit to 4 to keep remixes focused)
        if (prev.length >= 4) {
          toast.info('You can select up to 4 modifications')
          return prev
        }
        // Clear custom input when selecting suggestions
        setCustomInput('')
        return [...prev, suggestion]
      }
    })
  }

  const handleCustomInputChange = (value: string) => {
    setCustomInput(value)
    if (value.trim()) {
      // Clear suggestions when typing custom input
      setSelectedSuggestions([])
    }
  }

  const getModification = () => {
    if (customInput.trim()) {
      return customInput.trim()
    }
    if (selectedSuggestions.length === 1) {
      return selectedSuggestions[0]
    }
    if (selectedSuggestions.length > 1) {
      // Combine multiple suggestions into a natural sentence
      return selectedSuggestions.join(' AND ')
    }
    return null
  }

  const canSubmit = () => {
    return !creating && (selectedSuggestions.length > 0 || customInput.trim() !== '')
  }

  const handleCreateRemix = async () => {
    const modification = getModification()
    if (!modification) return

    setCreating(true)
    try {
      const remix = await api.ai.remix.create(recipe.id, modification, profileId)
      toast.success(`Created "${remix.title}"`)
      onRemixCreated(remix.id)
      onClose()
    } catch (error) {
      console.error('Failed to create remix:', error)
      toast.error('Failed to create remix')
    } finally {
      setCreating(false)
    }
  }

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4">
      <div className="relative w-full max-w-md rounded-xl bg-card shadow-2xl">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-border px-6 py-4">
          <div className="flex items-center gap-2">
            <Sparkles className="h-5 w-5 text-primary" />
            <h2 className="text-lg font-semibold text-foreground">Remix This Recipe</h2>
          </div>
          <button
            onClick={onClose}
            disabled={creating}
            className="rounded-full p-1 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        {/* Content */}
        <div className="px-6 py-5">
          <p className="mb-4 text-sm text-muted-foreground">
            Choose one or more modifications, or describe your own remix of "{recipe.title}"
          </p>

          {/* AI Suggestions */}
          <div className="mb-5">
            <div className="mb-3 flex items-center justify-between">
              <h3 className="text-sm font-medium text-foreground">Suggestions</h3>
              {selectedSuggestions.length > 0 && (
                <span className="text-xs text-muted-foreground">
                  {selectedSuggestions.length} selected
                </span>
              )}
            </div>
            {loadingSuggestions ? (
              <div className="flex items-center justify-center py-8">
                <Loader2 className="h-6 w-6 animate-spin text-primary" />
                <span className="ml-2 text-sm text-muted-foreground">
                  Generating suggestions...
                </span>
              </div>
            ) : (
              <div className="flex flex-wrap gap-2">
                {suggestions.map((suggestion, index) => {
                  const isSelected = selectedSuggestions.includes(suggestion)
                  return (
                    <button
                      key={index}
                      onClick={() => handleSuggestionClick(suggestion)}
                      disabled={creating}
                      className={cn(
                        'flex items-center gap-1.5 rounded-full px-3 py-1.5 text-sm transition-colors',
                        isSelected
                          ? 'bg-primary text-primary-foreground'
                          : 'bg-muted text-foreground hover:bg-muted/80'
                      )}
                    >
                      {isSelected && <Check className="h-3.5 w-3.5" />}
                      {suggestion}
                    </button>
                  )
                })}
              </div>
            )}
          </div>

          {/* Custom Input */}
          <div className="mb-5">
            <label
              htmlFor="custom-remix"
              className="mb-2 block text-sm font-medium text-foreground"
            >
              Or describe your own remix
            </label>
            <input
              id="custom-remix"
              type="text"
              value={customInput}
              onChange={(e) => handleCustomInputChange(e.target.value)}
              disabled={creating}
              placeholder="e.g., Make it gluten-free"
              className="w-full rounded-lg border border-border bg-background px-4 py-2.5 text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-50"
            />
          </div>

          {/* Create Button */}
          <button
            onClick={handleCreateRemix}
            disabled={!canSubmit()}
            className={cn(
              'flex w-full items-center justify-center gap-2 rounded-lg px-4 py-3 text-sm font-medium transition-colors',
              canSubmit()
                ? 'bg-primary text-primary-foreground hover:bg-primary/90'
                : 'bg-muted text-muted-foreground cursor-not-allowed'
            )}
          >
