import { Timer as TimerIcon, Plus, ChevronUp, ChevronDown, Sparkles, Loader2 } from 'lucide-react'
import { useState } from 'react'
import type { UseTimersReturn } from '../hooks/useTimers'
import { detectTimes } from '../hooks/useTimers'
import TimerWidget from './TimerWidget'
import { api } from '../api/client'

interface TimerPanelProps {
  timers: UseTimersReturn
  instructionText?: string
  aiAvailable?: boolean
}

const QUICK_TIMERS = [
  { label: '+5 min', duration: 5 * 60 },
  { label: '+10 min', duration: 10 * 60 },
  { label: '+15 min', duration: 15 * 60 },
]

export default function TimerPanel({ timers, instructionText, aiAvailable = false }: TimerPanelProps) {
  const [expanded, setExpanded] = useState(true)
  const [loadingTimerId, setLoadingTimerId] = useState<string | null>(null)

  // Detect times from current instruction
  const detectedTimes = instructionText ? detectTimes(instructionText) : []

  const formatDetectedTime = (seconds: number): string => {
    if (seconds >= 3600) {
      const hrs = Math.floor(seconds / 3600)
      const mins = Math.floor((seconds % 3600) / 60)
      return mins > 0 ? `${hrs}h ${mins}m` : `${hrs}h`
    }
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    if (mins === 0) return `${secs}s`
    if (secs === 0) return `${mins} min`
    return `${mins}m ${secs}s`
  }

  const handleAddTimer = async (id: string, fallbackLabel: string, duration: number) => {
    const durationMinutes = Math.ceil(duration / 60)

    // If AI is available and we have instruction text, try to get an AI-generated name
    if (aiAvailable && instructionText) {
      setLoadingTimerId(id)
      try {
        const response = await api.ai.timerName(instructionText, durationMinutes)
        timers.addTimer(response.label, duration)
      } catch {
        // AI failed, use fallback
        timers.addTimer(fallbackLabel, duration)
      } finally {
        setLoadingTimerId(null)
      }
    } else {
      // No AI available, use fallback label
      timers.addTimer(fallbackLabel, duration)
    }
  }

  const handleAddQuickTimer = (label: string, duration: number, index: number) => {
    handleAddTimer(`quick-${index}`, label, duration)
  }

  const handleAddDetectedTimer = (seconds: number, index: number) => {
    handleAddTimer(`detected-${index}`, formatDetectedTime(seconds), seconds)
  }

  const activeTimerCount = timers.timers.filter((t) => t.isRunning).length

  return (
    <div className="border-t border-border bg-card">
      {/* Header */}
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center justify-between px-4 py-3"
      >
        <div className="flex items-center gap-2">
          <TimerIcon className="h-5 w-5 text-primary" />
          <span className="font-medium text-foreground">Timers</span>
          {timers.timers.length > 0 && (
            <span className="rounded-full bg-muted px-2 py-0.5 text-xs text-muted-foreground">
              {timers.timers.length}
              {activeTimerCount > 0 && (
                <span className="text-primary"> ({activeTimerCount} active)</span>
              )}
            </span>
          )}
        </div>
        {expanded ? (
          <ChevronDown className="h-5 w-5 text-muted-foreground" />
        ) : (
          <ChevronUp className="h-5 w-5 text-muted-foreground" />
        )}
      </button>

      {expanded && (
        <div className="space-y-4 px-4 pb-4">
          {/* Quick timer buttons */}
          <div className="flex flex-wrap gap-2">
            {QUICK_TIMERS.map(({ label, duration }, idx) => (
              <button
                key={label}
                onClick={() => handleAddQuickTimer(label.replace('+', '').trim(), duration, idx)}
                disabled={loadingTimerId !== null}
                className="flex items-center gap-1 rounded-full border border-border bg-background px-3 py-1.5 text-sm text-foreground transition-colors hover:bg-muted disabled:opacity-50"
              >
                {loadingTimerId === `quick-${idx}` ? (
                  <Loader2 className="h-3 w-3 animate-spin" />
                ) : (
                  <Plus className="h-3 w-3" />
                )}
                {label}
              </button>
            ))}
            {aiAvailable && instructionText && <Sparkles className="h-4 w-4 text-primary self-center" />}
          </div>

          {/* Detected time suggestions */}
          {detectedTimes.length > 0 && (
            <div>
              <p className="mb-2 text-xs text-muted-foreground">
                Detected in this step:
              </p>
              <div className="flex flex-wrap gap-2">
                {detectedTimes.map((seconds, idx) => (
                  <button
                    key={idx}
                    onClick={() => handleAddDetectedTimer(seconds, idx)}
                    disabled={loadingTimerId !== null}
                    className="flex items-center gap-1 rounded-full bg-primary/10 px-3 py-1.5 text-sm text-primary transition-colors hover:bg-primary/20 disabled:opacity-50"
                  >
                    {loadingTimerId === `detected-${idx}` ? (
                      <Loader2 className="h-3 w-3 animate-spin" />
                    ) : (
                      <Plus className="h-3 w-3" />
                    )}
                    {formatDetectedTime(seconds)}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Timer list */}
          {timers.timers.length > 0 ? (
            <div className="space-y-2">
              {timers.timers.map((timer) => (
                <TimerWidget
                  key={timer.id}
                  timer={timer}
                  onToggle={() => timers.toggleTimer(timer.id)}
                  onReset={() => timers.resetTimer(timer.id)}
                  onDelete={() => timers.deleteTimer(timer.id)}
                />
              ))}
            </div>
          ) : (
            <p className="text-center text-sm text-muted-foreground">
              No active timers. Add one above!
            </p>
          )}
        </div>
      )}
    </div>
  )
}

import { Play, Pause, RotateCcw, X } from 'lucide-react'
import type { Timer } from '../hooks/useTimers'
import { formatTimerDisplay } from '../hooks/useTimers'
import { cn } from '../lib/utils'

interface TimerWidgetProps {
  timer: Timer
  onToggle: () => void
  onReset: () => void
  onDelete: () => void
}

export default function TimerWidget({
  timer,
  onToggle,
  onReset,
  onDelete,
}: TimerWidgetProps) {
  const isComplete = timer.remaining === 0
  const progress = ((timer.duration - timer.remaining) / timer.duration) * 100

  return (
    <div
      className={cn(
        'relative overflow-hidden rounded-lg border bg-card p-3',
        isComplete && 'border-accent bg-accent/10'
      )}
    >
      {/* Progress bar background */}
      <div
        className={cn(
          'absolute inset-0 opacity-20 transition-all',
          isComplete ? 'bg-accent' : 'bg-primary'
        )}
        style={{ width: `${progress}%` }}
      />

      {/* Content */}
      <div className="relative flex items-center justify-between">
        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-medium text-card-foreground">
            {timer.label}
          </p>
          <p
            className={cn(
              'text-2xl font-mono font-bold tabular-nums',
              isComplete ? 'text-accent' : 'text-foreground'
            )}
          >
            {formatTimerDisplay(timer.remaining)}
          </p>
        </div>

        <div className="flex items-center gap-1">
          {!isComplete && (
            <>
              <button
                onClick={onToggle}
                className={cn(
                  'rounded-full p-2 transition-colors',
                  timer.isRunning
                    ? 'bg-muted text-muted-foreground hover:bg-muted/80'
                    : 'bg-primary text-primary-foreground hover:bg-primary/90'
                )}
                aria-label={timer.isRunning ? 'Pause' : 'Play'}
              >
                {timer.isRunning ? (
                  <Pause className="h-4 w-4" />
                ) : (
                  <Play className="h-4 w-4" />
                )}
              </button>
              <button
                onClick={onReset}
                className="rounded-full bg-muted p-2 text-muted-foreground transition-colors hover:bg-muted/80"
                aria-label="Reset"
              >
                <RotateCcw className="h-4 w-4" />
              </button>
            </>
          )}
          <button
            onClick={onDelete}
            className="rounded-full bg-muted p-2 text-muted-foreground transition-colors hover:bg-destructive hover:text-destructive-foreground"
            aria-label="Delete"
          >
            <X className="h-4 w-4" />
          </button>
        </div>
      </div>
    </div>
  )
}

import { useState } from 'react'
import { Key, Check, AlertCircle, Loader2, Github, Moon, Sun } from 'lucide-react'
import { toast } from 'sonner'
import { api, type AIStatus, type AIModel } from '../../api/client'
import { useAIStatus } from '../../contexts/AIStatusContext'
import { useProfile } from '../../contexts/ProfileContext'
import { cn } from '../../lib/utils'

interface SettingsGeneralProps {
  aiStatus: AIStatus | null
  models: AIModel[]
  onAIStatusChange: (status: AIStatus) => void
  onModelsChange: (models: AIModel[]) => void
}

export default function SettingsGeneral({
  aiStatus,
  models,
  onAIStatusChange,
  onModelsChange,
}: SettingsGeneralProps) {
  const globalAIStatus = useAIStatus()
  const [apiKey, setApiKey] = useState('')
  const [testingKey, setTestingKey] = useState(false)
  const [savingKey, setSavingKey] = useState(false)

  const getModelName = (modelId: string) => {
    const model = models.find((m) => m.id === modelId)
    return model?.name || modelId
  }

  const handleTestApiKey = async () => {
    if (!apiKey.trim()) {
      toast.error('Please enter an API key')
      return
    }

    setTestingKey(true)
    try {
      const result = await api.ai.testApiKey(apiKey.trim())
      if (result.success) {
        toast.success(result.message)
      } else {
        toast.error(result.message)
      }
    } catch (error) {
      console.error('Failed to test API key:', error)
      toast.error('Failed to test API key')
    } finally {
      setTestingKey(false)
    }
  }

  const handleSaveApiKey = async () => {
    if (!apiKey.trim()) {
      toast.error('Please enter an API key')
      return
    }

    setSavingKey(true)
    try {
      const result = await api.ai.saveApiKey(apiKey.trim())
      if (result.success) {
        toast.success(result.message)
        setApiKey('')
        const statusData = await api.ai.status()
        onAIStatusChange(statusData)
        await globalAIStatus.refresh()
        const modelsData = await api.ai.models()
        onModelsChange(modelsData)
      } else {
        toast.error(result.message)
      }
    } catch (error) {
      console.error('Failed to save API key:', error)
      toast.error('Failed to save API key')
    } finally {
      setSavingKey(false)
    }
  }

  const { theme, toggleTheme } = useProfile()

  return (
    <div className="space-y-6">
      {/* Preferences */}
      <div className="rounded-lg border border-border bg-card p-4">
        <h2 className="mb-4 text-lg font-medium text-foreground">Preferences</h2>

        {/* Theme toggle */}
        <div className="mb-4">
          <label className="mb-2 block text-sm font-medium text-foreground">Theme</label>
          <div className="flex gap-2">
            <button
              onClick={() => theme !== 'light' && toggleTheme()}
              className={cn(
                'flex items-center gap-2 rounded-lg border px-4 py-2 text-sm font-medium transition-colors',
                theme === 'light'
                  ? 'border-primary bg-primary text-primary-foreground'
                  : 'border-border bg-background text-foreground hover:bg-muted'
              )}
            >
              <Sun className="h-4 w-4" />
              Light
            </button>
            <button
              onClick={() => theme !== 'dark' && toggleTheme()}
              className={cn(
                'flex items-center gap-2 rounded-lg border px-4 py-2 text-sm font-medium transition-colors',
                theme === 'dark'
                  ? 'border-primary bg-primary text-primary-foreground'
                  : 'border-border bg-background text-foreground hover:bg-muted'
              )}
            >
              <Moon className="h-4 w-4" />
              Dark
            </button>
          </div>
        </div>

        {/* Unit preference hidden until fully implemented */}
      </div>

      {/* OpenRouter API */}
      <div className="rounded-lg border border-border bg-card p-4">
        <h2 className="mb-4 text-lg font-medium text-foreground">OpenRouter API</h2>

        <div className="mb-4 flex items-center gap-2">
          <div
            className={cn(
              'h-2 w-2 rounded-full',
              aiStatus?.available
                ? 'bg-green-500'
                : aiStatus?.configured
                  ? 'bg-yellow-500'
                  : 'bg-red-500'
            )}
          />
          <span className="text-sm text-muted-foreground">
            {aiStatus?.available
              ? 'Connected'
              : aiStatus?.configured
                ? 'Invalid key'
                : 'Not configured'}
          </span>
        </div>

        {aiStatus?.configured && !aiStatus?.valid && (
          <div className="mb-4 flex items-center gap-2 rounded-lg border border-yellow-500/50 bg-yellow-500/10 p-3">
            <AlertCircle className="h-5 w-5 flex-shrink-0 text-yellow-500" />
            <p className="text-sm text-yellow-600 dark:text-yellow-400">
              {aiStatus?.error ||
                'Your API key appears to be invalid or expired. Please update it.'}
            </p>
          </div>
        )}

        {aiStatus?.available && (
          <div className="mb-4 text-sm text-muted-foreground">
            Default model:{' '}
            <span className="font-medium text-foreground">
              {getModelName(aiStatus.default_model)}
