                    </button>
                    <button
                      onClick={handleSavePrompt}
                      disabled={savingPrompt}
                      className="flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:cursor-not-allowed disabled:opacity-50"
                    >
                      {savingPrompt ? (
                        <Loader2 className="h-4 w-4 animate-spin" />
                      ) : (
                        <Check className="h-4 w-4" />
                      )}
                      Save Changes
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        )
      })}
    </div>
  )
}

import { useState } from 'react'
import { Check, Loader2, Play, CheckCircle, XCircle, HelpCircle } from 'lucide-react'
import { toast } from 'sonner'
import { api, type Source } from '../../api/client'

interface SettingsSelectorsProps {
  sources: Source[]
  onSourcesChange: (sources: Source[]) => void
}

export default function SettingsSelectors({
  sources,
  onSourcesChange,
}: SettingsSelectorsProps) {
  const [editingSourceId, setEditingSourceId] = useState<number | null>(null)
  const [editingSelectorValue, setEditingSelectorValue] = useState('')
  const [savingSelector, setSavingSelector] = useState(false)
  const [testingSourceId, setTestingSourceId] = useState<number | null>(null)
  const [testingAll, setTestingAll] = useState(false)

  const getSourceStatus = (source: Source): 'working' | 'broken' | 'untested' => {
    if (!source.last_validated_at) return 'untested'
    if (source.needs_attention || source.consecutive_failures >= 3) return 'broken'
    return 'working'
  }

  const formatRelativeTime = (dateStr: string | null): string => {
    if (!dateStr) return 'Never'
    const date = new Date(dateStr)
    const now = new Date()
    const diffMs = now.getTime() - date.getTime()
    const diffMins = Math.floor(diffMs / 60000)
    if (diffMins < 1) return 'Just now'
    if (diffMins < 60) return `${diffMins}m ago`
    const diffHours = Math.floor(diffMins / 60)
    if (diffHours < 24) return `${diffHours}h ago`
    const diffDays = Math.floor(diffHours / 24)
    return `${diffDays}d ago`
  }

  const handleEditSelector = (source: Source) => {
    setEditingSourceId(source.id)
    setEditingSelectorValue(source.result_selector)
  }

  const handleCancelEditSelector = () => {
    setEditingSourceId(null)
    setEditingSelectorValue('')
  }

  const handleSaveSelector = async () => {
    if (editingSourceId === null) return

    setSavingSelector(true)
    try {
      const result = await api.sources.updateSelector(
        editingSourceId,
        editingSelectorValue
      )
      onSourcesChange(
        sources.map((s) =>
          s.id === editingSourceId
            ? { ...s, result_selector: result.result_selector }
            : s
        )
      )
      toast.success('Selector updated')
      setEditingSourceId(null)
      setEditingSelectorValue('')
    } catch (error) {
      console.error('Failed to update selector:', error)
      toast.error('Failed to update selector')
    } finally {
      setSavingSelector(false)
    }
  }

  const handleTestSource = async (sourceId: number) => {
    setTestingSourceId(sourceId)
    try {
      const result = await api.sources.test(sourceId)
      if (result.success) {
        toast.success(result.message)
      } else {
        toast.error(result.message)
      }
      // Refresh sources to update status
      const sourcesData = await api.sources.list()
      onSourcesChange(sourcesData)
    } catch (error) {
      console.error('Failed to test source:', error)
      toast.error('Failed to test source')
    } finally {
      setTestingSourceId(null)
    }
  }

  const handleTestAllSources = async () => {
    setTestingAll(true)
    try {
      const result = await api.sources.testAll()
      toast.success(
        `Tested ${result.tested} sources: ${result.passed} passed, ${result.failed} failed`
      )
      // Refresh sources
      const sourcesData = await api.sources.list()
      onSourcesChange(sourcesData)
    } catch (error) {
      console.error('Failed to test all sources:', error)
      toast.error('Failed to test all sources')
    } finally {
      setTestingAll(false)
    }
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between rounded-lg border border-border bg-card p-4">
        <div>
          <h2 className="text-lg font-medium text-foreground">
            Search Source Selector Management
          </h2>
          <p className="text-sm text-muted-foreground">
            Edit CSS selectors and test source connectivity
          </p>
        </div>
        <button
          onClick={handleTestAllSources}
          disabled={testingAll}
          className="flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:cursor-not-allowed disabled:opacity-50"
        >
          {testingAll ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Play className="h-4 w-4" />
          )}
          Test All Sources
        </button>
      </div>

      <div className="space-y-3">
        {sources.map((source) => {
          const status = getSourceStatus(source)
          const isEditing = editingSourceId === source.id
          const isTesting = testingSourceId === source.id

          return (
            <div
              key={source.id}
              className="rounded-lg border border-border bg-card p-4"
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <span className="font-medium text-foreground">
                      {source.name}
                    </span>
                    {status === 'working' && (
                      <CheckCircle className="h-4 w-4 text-green-500" />
                    )}
                    {status === 'broken' && (
                      <XCircle className="h-4 w-4 text-red-500" />
                    )}
                    {status === 'untested' && (
                      <HelpCircle className="h-4 w-4 text-muted-foreground" />
                    )}
                  </div>
                  <p className="text-sm text-muted-foreground">{source.host}</p>
                  {source.consecutive_failures >= 3 && (
                    <p className="mt-1 text-xs text-red-500">
                      Failed {source.consecutive_failures} times - auto-disabled
                    </p>
                  )}
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-xs text-muted-foreground">
                    Last tested: {formatRelativeTime(source.last_validated_at)}
                  </span>
                  <button
                    onClick={() => handleTestSource(source.id)}
                    disabled={isTesting || testingAll}
                    className="flex items-center gap-1 rounded-lg border border-border bg-background px-3 py-1.5 text-sm font-medium text-foreground transition-colors hover:bg-muted disabled:cursor-not-allowed disabled:opacity-50"
                  >
                    {isTesting ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <Play className="h-4 w-4" />
                    )}
                    Test
                  </button>
                </div>
              </div>

              <div className="mt-3">
                <label className="mb-1 block text-xs font-medium text-muted-foreground">
                  CSS Selector
                </label>
                {isEditing ? (
                  <div className="flex gap-2">
                    <input
                      type="text"
                      value={editingSelectorValue}
                      onChange={(e) => setEditingSelectorValue(e.target.value)}
                      className="flex-1 rounded-lg border border-border bg-input-background px-3 py-1.5 font-mono text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-ring"
                    />
                    <button
                      onClick={handleCancelEditSelector}
                      className="rounded-lg border border-border bg-background px-3 py-1.5 text-sm font-medium text-foreground transition-colors hover:bg-muted"
                    >
                      Cancel
                    </button>
                    <button
                      onClick={handleSaveSelector}
                      disabled={savingSelector}
                      className="flex items-center gap-1 rounded-lg bg-primary px-3 py-1.5 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:cursor-not-allowed disabled:opacity-50"
                    >
                      {savingSelector ? (
                        <Loader2 className="h-4 w-4 animate-spin" />
                      ) : (
                        <Check className="h-4 w-4" />
                      )}
                      Save
                    </button>
                  </div>
                ) : (
                  <div className="flex items-center gap-2">
                    <code className="flex-1 rounded bg-muted px-3 py-1.5 font-mono text-sm text-foreground">
                      {source.result_selector || '(none)'}
                    </code>
                    <button
                      onClick={() => handleEditSelector(source)}
                      className="rounded-lg bg-primary/10 px-3 py-1.5 text-sm font-medium text-primary transition-colors hover:bg-primary/20"
                    >
                      Edit
                    </button>
                  </div>
                )}
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}

import { useState } from 'react'
import { Loader2, ToggleLeft, ToggleRight } from 'lucide-react'
import { toast } from 'sonner'
import { api, type Source } from '../../api/client'
import { cn } from '../../lib/utils'

interface SettingsSourcesProps {
  sources: Source[]
  onSourcesChange: (sources: Source[]) => void
}

export default function SettingsSources({
  sources,
  onSourcesChange,
}: SettingsSourcesProps) {
  const [togglingSourceId, setTogglingSourceId] = useState<number | null>(null)
  const [bulkToggling, setBulkToggling] = useState(false)

  const enabledCount = sources.filter((s) => s.is_enabled).length

  const handleToggleSource = async (sourceId: number) => {
    setTogglingSourceId(sourceId)
    try {
      const result = await api.sources.toggle(sourceId)
      onSourcesChange(
        sources.map((s) =>
          s.id === sourceId ? { ...s, is_enabled: result.is_enabled } : s
        )
      )
    } catch (error) {
      console.error('Failed to toggle source:', error)
      toast.error('Failed to toggle source')
    } finally {
      setTogglingSourceId(null)
    }
  }

  const handleBulkToggle = async (enable: boolean) => {
    setBulkToggling(true)
    try {
      await api.sources.bulkToggle(enable)
      onSourcesChange(sources.map((s) => ({ ...s, is_enabled: enable })))
      toast.success(enable ? 'All sources enabled' : 'All sources disabled')
    } catch (error) {
      console.error('Failed to bulk toggle sources:', error)
      toast.error('Failed to update sources')
    } finally {
      setBulkToggling(false)
    }
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between rounded-lg border border-border bg-card p-4">
        <div>
          <h2 className="text-lg font-medium text-foreground">Recipe Sources</h2>
          <p className="text-sm text-muted-foreground">
            {enabledCount} of {sources.length} sources currently enabled
          </p>
        </div>
        <div className="flex gap-2">
          <button
            onClick={() => handleBulkToggle(true)}
            disabled={bulkToggling || enabledCount === sources.length}
            className="rounded-lg border border-border bg-background px-3 py-1.5 text-sm font-medium text-foreground transition-colors hover:bg-muted disabled:cursor-not-allowed disabled:opacity-50"
          >
            Enable All
          </button>
          <button
            onClick={() => handleBulkToggle(false)}
            disabled={bulkToggling || enabledCount === 0}
            className="rounded-lg border border-border bg-background px-3 py-1.5 text-sm font-medium text-foreground transition-colors hover:bg-muted disabled:cursor-not-allowed disabled:opacity-50"
          >
            Disable All
          </button>
        </div>
      </div>

      <div className="space-y-2">
        {sources.map((source) => (
          <div
            key={source.id}
            className={cn(
              'flex items-center justify-between rounded-lg border p-4 transition-colors',
              source.is_enabled
                ? 'border-border bg-card'
                : 'border-border/50 bg-muted/30'
            )}
          >
            <div className="flex-1">
              <div className="flex items-center gap-2">
                <span className="font-medium text-foreground">{source.name}</span>
                {source.is_enabled && (
                  <span className="rounded bg-green-500/10 px-2 py-0.5 text-xs font-medium text-green-600 dark:text-green-400">
                    Active
                  </span>
                )}
              </div>
              <p className="text-sm text-muted-foreground">{source.host}</p>
            </div>
            <button
              onClick={() => handleToggleSource(source.id)}
              disabled={togglingSourceId === source.id}
              className="text-muted-foreground transition-colors hover:text-foreground disabled:opacity-50"
            >
              {togglingSourceId === source.id ? (
                <Loader2 className="h-6 w-6 animate-spin" />
              ) : source.is_enabled ? (
                <ToggleRight className="h-8 w-8 text-primary" />
              ) : (
                <ToggleLeft className="h-8 w-8" />
              )}
            </button>
          </div>
        ))}
      </div>
    </div>
  )
}

import { useState } from 'react'
import { Trash2, AlertTriangle, Loader2 } from 'lucide-react'
import { toast } from 'sonner'
import { api, type ProfileWithStats, type DeletionPreview } from '../../api/client'
import { cn } from '../../lib/utils'

interface SettingsUsersProps {
  profiles: ProfileWithStats[]
  currentProfileId?: number
  onProfilesChange: (profiles: ProfileWithStats[]) => void
}

export default function SettingsUsers({
  profiles,
  currentProfileId,
  onProfilesChange,
}: SettingsUsersProps) {
  const [showDeleteModal, setShowDeleteModal] = useState(false)
  const [deletePreview, setDeletePreview] = useState<DeletionPreview | null>(null)
  const [deletingId, setDeletingId] = useState<number | null>(null)
  const [deleting, setDeleting] = useState(false)

  const formatDate = (dateStr: string): string => {
    return new Date(dateStr).toLocaleDateString()
  }

  const handleDeleteClick = async (profileId: number) => {
    try {
      const preview = await api.profiles.deletionPreview(profileId)
      setDeletePreview(preview)
      setDeletingId(profileId)
      setShowDeleteModal(true)
    } catch (error) {
      console.error('Failed to load deletion preview:', error)
      toast.error('Failed to load profile info')
    }
  }

  const handleConfirmDelete = async () => {
    if (!deletingId) return

    setDeleting(true)
    try {
      await api.profiles.delete(deletingId)
      onProfilesChange(profiles.filter((p) => p.id !== deletingId))
      toast.success('Profile deleted successfully')
      setShowDeleteModal(false)
      setDeletePreview(null)
      setDeletingId(null)
    } catch (error) {
      console.error('Failed to delete profile:', error)
      toast.error('Failed to delete profile')
    } finally {
      setDeleting(false)
    }
  }

  const handleCancelDelete = () => {
    setShowDeleteModal(false)
    setDeletePreview(null)
    setDeletingId(null)
  }

  return (
    <>
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-lg font-medium text-foreground">User Management</h2>
            <p className="text-sm text-muted-foreground">
              Manage user profiles and their data
            </p>
          </div>
          <span className="text-sm text-muted-foreground">
            {profiles.length} profile{profiles.length !== 1 ? 's' : ''}
          </span>
        </div>

        <div className="space-y-3">
          {profiles.map((profile) => {
            const isCurrent = profile.id === currentProfileId

            return (
              <div
                key={profile.id}
                className="flex items-center justify-between rounded-lg border border-border bg-card p-4"
              >
                <div className="flex items-center gap-3">
                  {/* Avatar */}
                  <div
                    className="h-10 w-10 rounded-full"
                    style={{ backgroundColor: profile.avatar_color }}
                  />
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="font-medium text-foreground">
                        {profile.name}
                      </span>
                      {isCurrent && (
                        <span className="rounded bg-primary/10 px-2 py-0.5 text-xs text-primary">
                          Current
                        </span>
                      )}
                    </div>
                    <div className="text-sm text-muted-foreground">
                      Created {formatDate(profile.created_at)}
                    </div>
                    <div className="text-xs text-muted-foreground">
                      {profile.stats.favorites} favorites ·{' '}
                      {profile.stats.collections} collections ·{' '}
                      {profile.stats.remixes} remixes
                    </div>
                  </div>
                </div>

                <button
                  onClick={() => handleDeleteClick(profile.id)}
                  disabled={isCurrent}
                  className={cn(
                    'rounded p-2 transition-colors',
                    isCurrent
                      ? 'cursor-not-allowed text-muted-foreground/50'
                      : 'text-muted-foreground hover:bg-destructive/10 hover:text-destructive'
                  )}
                  title={
                    isCurrent ? 'Cannot delete current profile' : 'Delete profile'
                  }
                >
                  <Trash2 className="h-5 w-5" />
                </button>
              </div>
            )
          })}
        </div>
      </div>

      {/* Delete Profile Modal */}
      {showDeleteModal && deletePreview && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          <div
            className="absolute inset-0 bg-black/50"
            onClick={handleCancelDelete}
          />
          <div className="relative w-full max-w-md rounded-lg border border-border bg-card p-6 shadow-lg">
            <div className="flex items-center gap-2 text-destructive">
              <AlertTriangle className="h-5 w-5" />
              <h3 className="text-lg font-medium">Delete Profile?</h3>
            </div>

            <div className="mt-4 space-y-4">
              {/* Profile info */}
              <div className="flex items-center gap-3">
                <div
                  className="h-12 w-12 rounded-full"
                  style={{ backgroundColor: deletePreview.profile.avatar_color }}
                />
                <div>
                  <div className="font-medium text-foreground">
                    {deletePreview.profile.name}
                  </div>
                  <div className="text-sm text-muted-foreground">
                    Created {formatDate(deletePreview.profile.created_at)}
                  </div>
                </div>
              </div>

              {/* Data summary */}
              <div className="rounded-lg border border-border bg-muted/50 p-3">
                <div className="mb-2 text-sm font-medium text-foreground">
                  Data to be deleted:
                </div>
                <ul className="space-y-1 text-sm text-muted-foreground">
                  {deletePreview.data_to_delete.remixes > 0 && (
                    <li>
                      • {deletePreview.data_to_delete.remixes} remixed recipe
                      {deletePreview.data_to_delete.remixes !== 1 ? 's' : ''} (
                      {deletePreview.data_to_delete.remix_images} images)
                    </li>
                  )}
                  {deletePreview.data_to_delete.favorites > 0 && (
                    <li>
                      • {deletePreview.data_to_delete.favorites} favorite
                      {deletePreview.data_to_delete.favorites !== 1 ? 's' : ''}
                    </li>
                  )}
                  {deletePreview.data_to_delete.collections > 0 && (
                    <li>
                      • {deletePreview.data_to_delete.collections} collection
                      {deletePreview.data_to_delete.collections !== 1 ? 's' : ''} (
                      {deletePreview.data_to_delete.collection_items} items)
                    </li>
                  )}
                  {deletePreview.data_to_delete.view_history > 0 && (
                    <li>
                      • {deletePreview.data_to_delete.view_history} view history
                      entries
                    </li>
                  )}
                  {(deletePreview.data_to_delete.scaling_cache > 0 ||
                    deletePreview.data_to_delete.discover_cache > 0) && (
                    <li>• Cached AI data</li>
                  )}
                  {deletePreview.data_to_delete.remixes === 0 &&
                    deletePreview.data_to_delete.favorites === 0 &&
                    deletePreview.data_to_delete.collections === 0 &&
                    deletePreview.data_to_delete.view_history === 0 &&
                    deletePreview.data_to_delete.scaling_cache === 0 &&
                    deletePreview.data_to_delete.discover_cache === 0 && (
                      <li>• No associated data</li>
                    )}
                </ul>
              </div>

              {/* Warning */}
              <div className="text-sm text-destructive">
                This action cannot be undone. All data will be permanently deleted.
              </div>
            </div>

            <div className="mt-6 flex justify-end gap-3">
              <button
                onClick={handleCancelDelete}
                className="rounded-lg border border-border bg-background px-4 py-2 text-sm font-medium text-foreground transition-colors hover:bg-muted"
              >
                Cancel
              </button>
              <button
                onClick={handleConfirmDelete}
                disabled={deleting}
                className="flex items-center gap-2 rounded-lg bg-destructive px-4 py-2 text-sm font-medium text-destructive-foreground transition-colors hover:bg-destructive/90 disabled:cursor-not-allowed disabled:opacity-50"
              >
                {deleting ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Trash2 className="h-4 w-4" />
                )}
                Delete Profile
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  )
}

import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react'
import { api } from '../api/client'
import type { AuthProfile, PasskeyUser } from '../api/types'

interface AuthContextType {
  user: PasskeyUser | null
  profile: AuthProfile | null
  isAdmin: boolean
  isLoading: boolean
  logout: () => Promise<void>
  refreshSession: () => Promise<void>
}

const AuthContext = createContext<AuthContextType | null>(null)

// eslint-disable-next-line react-refresh/only-export-components -- Hook is tightly coupled to provider
export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<PasskeyUser | null>(null)
  const [profile, setProfile] = useState<AuthProfile | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  // Restore session on mount
  useEffect(() => {
    api.auth
      .me()
      .then((data) => {
        setUser(data.user)
        setProfile(data.profile)
      })
      .catch(() => {
        // Not logged in
      })
      .finally(() => setIsLoading(false))
  }, [])

  const refreshSession = useCallback(async () => {
    try {
      const data = await api.auth.me()
      setUser(data.user)
      setProfile(data.profile)
    } catch {
      setUser(null)
      setProfile(null)
    }
  }, [])

  const logout = useCallback(async () => {
    try {
      await api.auth.logout()
    } catch {
      // Ignore errors on logout
    }
    setUser(null)
    setProfile(null)
  }, [])

  return (
    <AuthContext.Provider
      value={{
        user,
        profile,
        isAdmin: user?.is_admin ?? false,
        isLoading,
        logout,
        refreshSession,
      }}
    >
      {children}
    </AuthContext.Provider>
  )
}

import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react'
import { toast } from 'sonner'
import { api, type Profile, type RecipeDetail } from '../api/client'

const PROFILE_STORAGE_KEY = 'cookie_selected_profile_id'

function saveProfileId(id: number) {
  localStorage.setItem(PROFILE_STORAGE_KEY, String(id))
  document.cookie = `selected_profile_id=${id};path=/;SameSite=Lax`
}

function clearProfileId() {
  localStorage.removeItem(PROFILE_STORAGE_KEY)
  document.cookie = 'selected_profile_id=;path=/;expires=Thu, 01 Jan 1970 00:00:00 GMT'
}

function getStoredProfileId(): number | null {
  const stored = localStorage.getItem(PROFILE_STORAGE_KEY)
  if (!stored) return null
  const id = parseInt(stored, 10)
  return isNaN(id) ? null : id
}

interface ProfileContextType {
  profile: Profile | null
  theme: 'light' | 'dark'
  favoriteRecipeIds: Set<number>
  loading: boolean
  selectProfile: (profile: Profile) => Promise<void>
  logout: () => void
  toggleTheme: () => Promise<void>
  updateUnitPreference: (unit: 'metric' | 'imperial') => Promise<void>
  toggleFavorite: (recipe: RecipeDetail) => Promise<void>
  isFavorite: (recipeId: number) => boolean
}

const ProfileContext = createContext<ProfileContextType | null>(null)

// eslint-disable-next-line react-refresh/only-export-components -- Hook is tightly coupled to provider
export function useProfile() {
  const context = useContext(ProfileContext)
  if (!context) {
    throw new Error('useProfile must be used within a ProfileProvider')
  }
  return context
}

interface AuthProfile {
  id: number
  name: string
  avatar_color: string
  theme: string
  unit_preference: string
}

interface ProfileProviderProps {
  children: ReactNode
  authProfile?: AuthProfile | null
}

export function ProfileProvider({ children, authProfile }: ProfileProviderProps) {
  const [profile, setProfile] = useState<Profile | null>(null)
  const [theme, setTheme] = useState<'light' | 'dark'>('light')
  const [favoriteRecipeIds, setFavoriteRecipeIds] = useState<Set<number>>(new Set())
  const [loading, setLoading] = useState(true)

  // Apply theme class to document
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark')
    } else {
      document.documentElement.classList.remove('dark')
    }
  }, [theme])

  // In public mode, profile comes from auth
  useEffect(() => {
    if (authProfile !== undefined) {
      if (authProfile) {
        setProfile(authProfile as Profile)
        setTheme(authProfile.theme as 'light' | 'dark')
      } else {
        setProfile(null)
      }
      setLoading(false)
      return
    }

    // Home mode: restore from localStorage
    const restoreSession = async () => {
      try {
        const storedId = getStoredProfileId()
        if (storedId) {
          try {
            const restored = await api.profiles.select(storedId)
            setProfile(restored)
            setTheme(restored.theme as 'light' | 'dark')
          } catch {
            clearProfileId()
          }
        }
      } catch (error) {
        console.error('Failed to restore session:', error)
      } finally {
        setLoading(false)
      }
    }
    restoreSession()
  }, [authProfile])

  // Load favorites when profile changes
  useEffect(() => {
    // Clear favorites and skip API call if no profile
    if (!profile) {
      // Use callback form to satisfy react-hooks/set-state-in-effect
      Promise.resolve().then(() => setFavoriteRecipeIds(new Set()))
      return
    }

    api.favorites
      .list()
      .then((favorites) => setFavoriteRecipeIds(new Set(favorites.map((f) => f.recipe.id))))
      .catch((error) => console.error('Failed to load favorites:', error))
  }, [profile])

  const selectProfile = useCallback(async (selectedProfile: Profile) => {
    try {
      await api.profiles.select(selectedProfile.id)
      setProfile(selectedProfile)
      setTheme(selectedProfile.theme as 'light' | 'dark')
      saveProfileId(selectedProfile.id)
    } catch (error) {
      console.error('Failed to select profile:', error)
      throw error
    }
  }, [])

  const logout = useCallback(() => {
    setProfile(null)
    setFavoriteRecipeIds(new Set())
    clearProfileId()
  }, [])

  const toggleTheme = useCallback(async () => {
    if (!profile) return

    const newTheme = theme === 'light' ? 'dark' : 'light'
    setTheme(newTheme)

    try {
      const updated = await api.profiles.update(profile.id, {
        ...profile,
        theme: newTheme,
      })
      setProfile(updated)
    } catch (error) {
      console.error('Failed to update theme:', error)
      setTheme(theme) // Revert on error
    }
  }, [profile, theme])

  const updateUnitPreference = useCallback(async (unit: 'metric' | 'imperial') => {
    if (!profile) return

    const previousUnit = profile.unit_preference
    setProfile({ ...profile, unit_preference: unit })

    try {
      const updated = await api.profiles.update(profile.id, {
        ...profile,
        unit_preference: unit,
      })
      setProfile(updated)
    } catch (error) {
      console.error('Failed to update unit preference:', error)
      setProfile({ ...profile, unit_preference: previousUnit }) // Revert on error
    }
  }, [profile])

  const toggleFavorite = useCallback(async (recipe: RecipeDetail) => {
    const isFav = favoriteRecipeIds.has(recipe.id)
    try {
      if (isFav) {
        await api.favorites.remove(recipe.id)
        setFavoriteRecipeIds((prev) => {
          const next = new Set(prev)
          next.delete(recipe.id)
          return next
        })
        toast.success('Removed from favorites')
      } else {
        await api.favorites.add(recipe.id)
        setFavoriteRecipeIds((prev) => new Set(prev).add(recipe.id))
        toast.success('Added to favorites')
      }
    } catch (error) {
      console.error('Failed to toggle favorite:', error)
      toast.error('Failed to update favorites')
    }
  }, [favoriteRecipeIds])

  const isFavorite = useCallback((recipeId: number) => {
    return favoriteRecipeIds.has(recipeId)
  }, [favoriteRecipeIds])

  return (
    <ProfileContext.Provider
      value={{
        profile,
        theme,
        favoriteRecipeIds,
        loading,
        selectProfile,
        logout,
        toggleTheme,
        updateUnitPreference,
        toggleFavorite,
        isFavorite,
      }}
    >
      {children}
    </ProfileContext.Provider>
  )
}

import { useState, useEffect } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { toast } from 'sonner'
import {
  api,
  type RecipeDetail as RecipeDetailType,
  type ScaleResponse,
} from '../api/client'
import { useProfile } from '../contexts/ProfileContext'
import { useAIStatus } from '../contexts/AIStatusContext'

type Tab = 'ingredients' | 'instructions' | 'nutrition' | 'tips'

export function useRecipeDetail() {
  const navigate = useNavigate()
  const { id } = useParams<{ id: string }>()
  const recipeId = Number(id)
  const { profile, isFavorite, toggleFavorite } = useProfile()
  const aiStatus = useAIStatus()

  const [recipe, setRecipe] = useState<RecipeDetailType | null>(null)
  const [loading, setLoading] = useState(true)
  const [activeTab, setActiveTab] = useState<Tab>('ingredients')
  const [metaExpanded, setMetaExpanded] = useState(true)
  const [servings, setServings] = useState<number | null>(null)
  const [showRemixModal, setShowRemixModal] = useState(false)
  const [scaledData, setScaledData] = useState<ScaleResponse | null>(null)
  const [scalingLoading, setScalingLoading] = useState(false)
  const [tips, setTips] = useState<string[]>([])
  const [tipsLoading, setTipsLoading] = useState(false)
  const [tipsPolling, setTipsPolling] = useState(false)

  useEffect(() => {
    if (recipeId) {
      loadData()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- loadData is stable, only re-run when recipeId changes
  }, [recipeId])

  // Poll for tips if recipe is recently imported and has no tips yet
  useEffect(() => {
    if (!recipe) return

    const recipeAge = Date.now() - new Date(recipe.scraped_at).getTime()
    const isRecent = recipeAge < 60000 // 60 seconds

    // Only poll for recent recipes with no tips
    if (!isRecent || tips.length > 0) {
      setTipsPolling(false)
      return
    }

    setTipsPolling(true)
    const startTime = Date.now()
    const POLL_INTERVAL = 3000 // 3 seconds
    const MAX_POLL_DURATION = 30000 // 30 seconds

    const interval = setInterval(async () => {
      // Stop if we've been polling too long
      if (Date.now() - startTime > MAX_POLL_DURATION) {
        clearInterval(interval)
        setTipsPolling(false)
        return
      }

      try {
        const updated = await api.recipes.get(recipe.id)
        if (updated.ai_tips && updated.ai_tips.length > 0) {
          setTips(updated.ai_tips)
          setRecipe((prev) => prev ? { ...prev, ai_tips: updated.ai_tips } : prev)
          clearInterval(interval)
          setTipsPolling(false)
        }
      } catch {
        // Ignore polling errors, will retry on next interval
      }
    }, POLL_INTERVAL)

    return () => {
      clearInterval(interval)
      setTipsPolling(false)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- recipe object changes on fetch, only care about id/scraped_at/tips changes
  }, [recipe?.id, recipe?.scraped_at, tips.length])

  // Auto-generate tips when viewing Tips tab for old recipes without tips
  useEffect(() => {
    if (
      activeTab === 'tips' &&
      tips.length === 0 &&
      aiStatus.available &&
      !tipsLoading &&
      !tipsPolling &&
      recipe
    ) {
      handleGenerateTips(false)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- intentionally only trigger on tab change, other deps checked inside
  }, [activeTab])

  const loadData = async () => {
    try {
      const recipeData = await api.recipes.get(recipeId)
      setRecipe(recipeData)
      setServings(recipeData.servings)
      setTips(recipeData.ai_tips || [])
      // Reset scaled data when loading a new recipe
      setScaledData(null)
    } catch (error) {
      console.error('Failed to load recipe:', error)
      toast.error('Failed to load recipe')
    } finally {
      setLoading(false)
    }
  }

  const canShowServingAdjustment =
    aiStatus.available && recipe?.servings !== null

  const handleServingChange = async (delta: number) => {
    if (!servings || !recipe || !profile) return
    const newServings = Math.max(1, servings + delta)
    setServings(newServings)

    // If returning to original servings, clear scaled data
    if (newServings === recipe.servings) {
      setScaledData(null)
      return
    }

    // Call AI to scale ingredients
    setScalingLoading(true)
    try {
      const result = await api.ai.scale(recipe.id, newServings, profile.id)
      setScaledData(result)
      if (result.notes.length > 0) {
        toast.info(result.notes[0])
      }
    } catch (error) {
      console.error('Failed to scale recipe:', error)
      toast.error('Failed to scale ingredients')
      // Revert to previous servings on error
      setServings(servings)
    } finally {
      setScalingLoading(false)
    }
  }

  const handleGenerateTips = async (regenerate: boolean = false) => {
    if (!recipe || tipsLoading) return

    setTipsLoading(true)
    try {
      const result = await api.ai.tips(recipe.id, regenerate)
      setTips(result.tips)
      // Update the recipe object too
      setRecipe({ ...recipe, ai_tips: result.tips })
      toast.success(regenerate ? 'Tips regenerated!' : 'Tips generated!')
    } catch (error) {
      console.error('Failed to generate tips:', error)
      toast.error('Failed to generate tips')
    } finally {
      setTipsLoading(false)
    }
  }

  const handleFavoriteToggle = async () => {
    if (!recipe) return
    await toggleFavorite(recipe)
  }

  const handleStartCooking = () => {
    navigate(`/recipe/${recipeId}/play`)
  }

  const handleAddToNewCollection = () => {
    navigate(`/collections?addRecipe=${recipeId}`)
  }

  const handleRemixCreated = async (newRecipeId: number) => {
    // Record history so the remix shows in "Recently Viewed"
    try {
      await api.history.record(newRecipeId)
    } catch (error) {
      console.error('Failed to record history:', error)
    }
    navigate(`/recipe/${newRecipeId}`)
  }

  const handleBack = () => {
    navigate(-1)
  }

  const recipeIsFavorite = recipe ? isFavorite(recipe.id) : false
  const imageUrl = recipe ? (recipe.image || recipe.image_url) : null

  return {
    recipe,
    loading,
    activeTab,
    setActiveTab,
    metaExpanded,
    setMetaExpanded,
    servings,
    showRemixModal,
    setShowRemixModal,
    scaledData,
    scalingLoading,
    tips,
    tipsLoading,
    tipsPolling,
    profile,
    aiStatus,
    recipeId,
    canShowServingAdjustment,
    recipeIsFavorite,
    imageUrl,
    handleServingChange,
    handleGenerateTips,
    handleFavoriteToggle,
    handleStartCooking,
    handleAddToNewCollection,
    handleRemixCreated,
    handleBack,
  }
}

export type { Tab }

import { useState, useEffect, useRef, useCallback } from 'react'

export interface Timer {
  id: string
  label: string
  duration: number // seconds
  remaining: number // seconds
  isRunning: boolean
}

export interface UseTimersReturn {
  timers: Timer[]
  addTimer: (label: string, duration: number, autoStart?: boolean) => string
  startTimer: (id: string) => void
  pauseTimer: (id: string) => void
  resetTimer: (id: string) => void
  deleteTimer: (id: string) => void
  toggleTimer: (id: string) => void
}

export function useTimers(onTimerComplete?: (timer: Timer) => void): UseTimersReturn {
  const [timers, setTimers] = useState<Timer[]>([])
  const intervalsRef = useRef<Map<string, number>>(new Map())
  const onCompleteRef = useRef(onTimerComplete)

  // Keep callback ref up to date
  useEffect(() => {
    onCompleteRef.current = onTimerComplete
  }, [onTimerComplete])

  // Cleanup intervals on unmount
  useEffect(() => {
    const intervals = intervalsRef.current
    return () => {
      intervals.forEach((intervalId) => {
        clearInterval(intervalId)
      })
    }
  }, [])

  const addTimer = useCallback((label: string, duration: number, autoStart: boolean = true): string => {
    const id = crypto.randomUUID()

    // Add timer to state FIRST to ensure it exists before interval ticks
    setTimers((prev) => [
      ...prev,
      {
        id,
        label,
        duration,
        remaining: duration,
        isRunning: autoStart,
      },
    ])

    // Set up interval AFTER state update is queued (timer will exist before first tick)
    if (autoStart) {
      const intervalId = window.setInterval(() => {
        setTimers((prev) =>
          prev.map((timer) => {
            if (timer.id !== id) return timer
            if (!timer.isRunning) return timer

            const newRemaining = timer.remaining - 1

            if (newRemaining <= 0) {
              // Timer completed
              clearInterval(intervalsRef.current.get(id))
              intervalsRef.current.delete(id)
              onCompleteRef.current?.({ ...timer, remaining: 0, isRunning: false })
              return { ...timer, remaining: 0, isRunning: false }
            }

            return { ...timer, remaining: newRemaining }
          })
        )
      }, 1000)

      intervalsRef.current.set(id, intervalId)
    }

    return id
  }, [])

  const startTimer = useCallback((id: string) => {
    // Clear any existing interval for this timer
    const existingInterval = intervalsRef.current.get(id)
    if (existingInterval) {
      clearInterval(existingInterval)
    }

    // Start new interval
    const intervalId = window.setInterval(() => {
      setTimers((prev) =>
        prev.map((timer) => {
          if (timer.id !== id) return timer
          if (!timer.isRunning) return timer

          const newRemaining = timer.remaining - 1

          if (newRemaining <= 0) {
            // Timer completed
            clearInterval(intervalsRef.current.get(id))
            intervalsRef.current.delete(id)
            onCompleteRef.current?.({ ...timer, remaining: 0, isRunning: false })
            return { ...timer, remaining: 0, isRunning: false }
          }

          return { ...timer, remaining: newRemaining }
        })
      )
    }, 1000)

    intervalsRef.current.set(id, intervalId)

    setTimers((prev) =>
      prev.map((timer) =>
        timer.id === id ? { ...timer, isRunning: true } : timer
      )
    )
  }, [])

  const pauseTimer = useCallback((id: string) => {
    // Clear interval
    const intervalId = intervalsRef.current.get(id)
    if (intervalId) {
      clearInterval(intervalId)
      intervalsRef.current.delete(id)
    }

    setTimers((prev) =>
      prev.map((timer) =>
        timer.id === id ? { ...timer, isRunning: false } : timer
      )
    )
  }, [])

  const resetTimer = useCallback((id: string) => {
    // Clear interval
    const intervalId = intervalsRef.current.get(id)
    if (intervalId) {
      clearInterval(intervalId)
      intervalsRef.current.delete(id)
    }

    setTimers((prev) =>
      prev.map((timer) =>
        timer.id === id
          ? { ...timer, remaining: timer.duration, isRunning: false }
          : timer
      )
    )
  }, [])

  const deleteTimer = useCallback((id: string) => {
    // Clear interval
    const intervalId = intervalsRef.current.get(id)
    if (intervalId) {
      clearInterval(intervalId)
      intervalsRef.current.delete(id)
    }

    setTimers((prev) => prev.filter((timer) => timer.id !== id))
  }, [])

  const toggleTimer = useCallback(
    (id: string) => {
      const timer = timers.find((t) => t.id === id)
      if (!timer) return

      if (timer.isRunning) {
        pauseTimer(id)
      } else {
        startTimer(id)
      }
    },
    [timers, pauseTimer, startTimer]
  )

  return {
    timers,
    addTimer,
    startTimer,
    pauseTimer,
    resetTimer,
    deleteTimer,
    toggleTimer,
  }
}

/**
 * Detects time mentions in text and returns durations in seconds.
 *
 * Supports patterns like:
 * - "15 minutes", "15 min", "15m"
 * - "2 hours", "2 hr", "2h"
 * - "30 seconds", "30 sec", "30s"
 */
export function detectTimes(text: string): number[] {
  const times: number[] = []
  const seen = new Set<string>()

  // Patterns for different time units
  const patterns = [
    { regex: /(\d+)\s*(?:hours?|hrs?|h)\b/gi, multiplier: 3600 },
    { regex: /(\d+)\s*(?:minutes?|mins?|m)\b/gi, multiplier: 60 },
    { regex: /(\d+)\s*(?:seconds?|secs?|s)\b/gi, multiplier: 1 },
  ]

  for (const { regex, multiplier } of patterns) {
    let match
    while ((match = regex.exec(text)) !== null) {
      const value = parseInt(match[1], 10)
      const seconds = value * multiplier
      const key = `${match.index}-${value}-${multiplier}`
      if (!seen.has(key) && seconds > 0) {
        seen.add(key)
        times.push(seconds)
      }
    }
  }

  // Sort by appearance in text (earlier matches first)
  return times
}

/**
 * Formats seconds as a human-readable time string.
 * e.g., 90 -> "1:30", 3661 -> "1:01:01"
 */
export function formatTimerDisplay(seconds: number): string {
  const hrs = Math.floor(seconds / 3600)
  const mins = Math.floor((seconds % 3600) / 60)
  const secs = seconds % 60

  if (hrs > 0) {
    return `${hrs}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`
  }
  return `${mins}:${secs.toString().padStart(2, '0')}`
}

