/**
 * useWakeLock - Prevents the screen from locking while active
 *
 * Uses the Screen Wake Lock API (iOS 16.4+, Chrome 84+) with a silent video
 * fallback for older browsers.
 *
 * @param enabled - Whether wake lock should be active (default: true)
 */
export function useWakeLock(enabled: boolean = true): void {
  const wakeLockRef = useRef<WakeLockSentinel | null>(null)
  const videoRef = useRef<HTMLVideoElement | null>(null)
  const usingFallbackRef = useRef(false)

  // Check if Screen Wake Lock API is supported
  const isWakeLockSupported = useCallback(() => {
    return 'wakeLock' in navigator
  }, [])

  // Request wake lock using native API
  const requestWakeLock = useCallback(async () => {
    if (!isWakeLockSupported()) {
      return false
    }

    try {
      wakeLockRef.current = await navigator.wakeLock.request('screen')

      // Re-acquire wake lock if released (e.g., tab becomes visible again)
      wakeLockRef.current.addEventListener('release', () => {
        wakeLockRef.current = null
      })

      return true
    } catch {
      // Wake lock request failed (e.g., low battery, permissions)
      return false
    }
  }, [isWakeLockSupported])

  // Release wake lock
  const releaseWakeLock = useCallback(async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release()
      } catch {
        // Ignore release errors
      }
      wakeLockRef.current = null
    }
  }, [])

  // Start video fallback for older browsers
  const startVideoFallback = useCallback(() => {
    if (videoRef.current) {
      return // Already created
    }

    const video = document.createElement('video')
    video.setAttribute('playsinline', '')
    video.setAttribute('muted', '')
    video.setAttribute('loop', '')
    video.muted = true
    video.src = SILENT_VIDEO_BASE64
    video.style.position = 'fixed'
    video.style.top = '-9999px'
    video.style.left = '-9999px'
    video.style.width = '1px'
    video.style.height = '1px'
    video.style.opacity = '0.01'

    document.body.appendChild(video)
    videoRef.current = video

    // Try to play (may require user interaction on iOS)
    video.play().catch(() => {
      // Silent fail - will try again on user interaction
    })

    usingFallbackRef.current = true
  }, [])

  // Stop video fallback
  const stopVideoFallback = useCallback(() => {
    if (videoRef.current) {
      videoRef.current.pause()
      videoRef.current.remove()
      videoRef.current = null
    }
    usingFallbackRef.current = false
  }, [])

  // Main effect to manage wake lock lifecycle
  useEffect(() => {
    if (!enabled) {
      releaseWakeLock()
      stopVideoFallback()
      return
    }

    let mounted = true

    const enableWakeLock = async () => {
      // Try native API first
      const success = await requestWakeLock()

      if (!success && mounted) {
        // Fall back to video technique
        startVideoFallback()
      }
    }

    enableWakeLock()

    // Re-acquire wake lock when page becomes visible
    const handleVisibilityChange = async () => {
      if (document.visibilityState === 'visible' && mounted && enabled) {
        if (!usingFallbackRef.current) {
          await requestWakeLock()
        }
      }
    }

    document.addEventListener('visibilitychange', handleVisibilityChange)

    return () => {
      mounted = false
      releaseWakeLock()
      stopVideoFallback()
      document.removeEventListener('visibilitychange', handleVisibilityChange)
    }
  }, [enabled, requestWakeLock, releaseWakeLock, startVideoFallback, stopVideoFallback])
}

/**
 * Base64url encode/decode utilities for WebAuthn binary fields.
 */

export function base64urlEncode(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer)
  let binary = ''
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i])
  }
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

export function base64urlDecode(str: string): ArrayBuffer {
  // Add padding
  let base64 = str.replace(/-/g, '+').replace(/_/g, '/')
  while (base64.length % 4 !== 0) {
    base64 += '='
  }
  const binary = atob(base64)
  const bytes = new Uint8Array(binary.length)
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i)
  }
  return bytes.buffer
}

/**
 * Prepare PublicKeyCredentialCreationOptions from server JSON.
 * Converts base64url strings to ArrayBuffers where the WebAuthn API expects them.
 */
export function prepareRegistrationOptions(
  options: Record<string, unknown>
): PublicKeyCredentialCreationOptions {
  const publicKey = (options.publicKey ?? options) as Record<string, unknown>

  return {
    ...publicKey,
    challenge: base64urlDecode(publicKey.challenge as string),
    user: {
      ...(publicKey.user as Record<string, unknown>),
      id: base64urlDecode((publicKey.user as Record<string, string>).id),
    },
    excludeCredentials: ((publicKey.excludeCredentials as Array<Record<string, unknown>>) ?? []).map(
      (cred) => ({
        ...cred,
        id: base64urlDecode(cred.id as string),
      })
    ),
  } as PublicKeyCredentialCreationOptions
}

/**
 * Prepare PublicKeyCredentialRequestOptions from server JSON.
 */
export function prepareAuthenticationOptions(
  options: Record<string, unknown>
): PublicKeyCredentialRequestOptions {
  const publicKey = (options.publicKey ?? options) as Record<string, unknown>

  return {
    ...publicKey,
    challenge: base64urlDecode(publicKey.challenge as string),
    allowCredentials: ((publicKey.allowCredentials as Array<Record<string, unknown>>) ?? []).map(
      (cred) => ({
        ...cred,
        id: base64urlDecode(cred.id as string),
      })
    ),
  } as PublicKeyCredentialRequestOptions
}

/**
 * Serialize a registration credential response for sending to the server.
 */
export function serializeRegistrationCredential(
  credential: PublicKeyCredential
): Record<string, unknown> {
  const response = credential.response as AuthenticatorAttestationResponse
  return {
    id: credential.id,
    rawId: base64urlEncode(credential.rawId),
    type: credential.type,
    response: {
      attestationObject: base64urlEncode(response.attestationObject),
      clientDataJSON: base64urlEncode(response.clientDataJSON),
    },
    authenticatorAttachment: (credential as unknown as Record<string, string>).authenticatorAttachment,
  }
}

/**
 * Serialize an authentication credential response for sending to the server.
 */
export function serializeAuthenticationCredential(
  credential: PublicKeyCredential
): Record<string, unknown> {
  const response = credential.response as AuthenticatorAssertionResponse
  return {
    id: credential.id,
    rawId: base64urlEncode(credential.rawId),
    type: credential.type,
    response: {
      authenticatorData: base64urlEncode(response.authenticatorData),
      clientDataJSON: base64urlEncode(response.clientDataJSON),
      signature: base64urlEncode(response.signature),
      userHandle: response.userHandle ? base64urlEncode(response.userHandle) : null,
    },
  }
}

import { createContext, lazy, Suspense, useContext, useState, useEffect } from 'react'
import { createBrowserRouter, Outlet, Navigate, useLocation } from 'react-router-dom'
