const CollectionDetail = lazy(() => import('./screens/CollectionDetail'))
const Settings = lazy(() => import('./screens/Settings'))
const PairDevice = lazy(() => import('./screens/PairDevice'))
const PasskeyManage = lazy(() => import('./screens/PasskeyManage'))

function LoadingFallback() {
  return (
    <div className="flex min-h-screen items-center justify-center bg-background">
      <div className="text-muted-foreground">Loading...</div>
    </div>
  )
}

// Mode context — provides the operating mode to child components without hook violations
const ModeContext = createContext<'home' | 'passkey'>('home')

export function useMode() {
  return useContext(ModeContext)
}

// eslint-disable-next-line react-refresh/only-export-components -- Internal router component, not exported for reuse
function AppLayout() {
  const [mode, setMode] = useState<'home' | 'passkey' | null>(null)

  useEffect(() => {
    api.system
      .mode()
      .then((data) => setMode(data.mode === 'passkey' ? 'passkey' : 'home'))
      .catch(() => setMode('home'))
  }, [])

  if (mode === null) {
    return <LoadingFallback />
  }

  if (mode === 'passkey') {
    return (
      <ModeContext.Provider value="passkey">
        <AuthProvider>
          <AIStatusProvider>
            <AuthProfileBridge>
              <Toaster position="top-center" richColors />
              <Suspense fallback={<LoadingFallback />}>
                <Outlet />
              </Suspense>
            </AuthProfileBridge>
          </AIStatusProvider>
        </AuthProvider>
      </ModeContext.Provider>
    )
  }

  return (
    <ModeContext.Provider value="home">
      <AIStatusProvider>
        <ProfileProvider>
          <Toaster position="top-center" richColors />
          <Suspense fallback={<LoadingFallback />}>
            <Outlet />
          </Suspense>
        </ProfileProvider>
      </AIStatusProvider>
    </ModeContext.Provider>
  )
}

// eslint-disable-next-line react-refresh/only-export-components -- Internal router component, not exported for reuse
function AuthProfileBridge({ children }: { children: React.ReactNode }) {
  const { profile: authProfile, isLoading } = useAuth()

  if (isLoading) {
    return <LoadingFallback />
  }

  return <ProfileProvider authProfile={authProfile}>{children}</ProfileProvider>
}

// eslint-disable-next-line react-refresh/only-export-components -- Internal router component, not exported for reuse
function ProtectedRoute({ children }: { children: React.ReactNode }) {
  const { profile, loading } = useProfile()
  const location = useLocation()

  if (loading) {
    return <LoadingFallback />
  }

  if (!profile) {
    return <Navigate to="/" state={{ from: location }} replace />
  }

  return <>{children}</>
}

// eslint-disable-next-line react-refresh/only-export-components -- Internal router component, not exported for reuse
function PublicRoute({ children }: { children: React.ReactNode }) {
  const { profile, loading } = useProfile()

  if (loading) {
    return <LoadingFallback />
  }

  if (profile) {
    return <Navigate to="/home" replace />
  }

  return <>{children}</>
}

// eslint-disable-next-line react-refresh/only-export-components -- Internal router component, not exported for reuse
function RootRoute() {
  const mode = useMode()
  if (mode === 'passkey') {
    return <PasskeyLogin />
  }
  return <ProfileSelector />
}

export const router = createBrowserRouter([
  {
    element: <AppLayout />,
    children: [
      {
        path: '/',
