      loadCollection()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- loadCollection is stable, only re-run when collectionId changes
  }, [collectionId])

  const loadCollection = async () => {
    try {
      const data = await api.collections.get(collectionId)
      setCollection(data)
    } catch (error) {
      console.error('Failed to load collection:', error)
      toast.error('Failed to load collection')
    } finally {
      setLoading(false)
    }
  }

  const handleRemoveRecipe = async (recipe: Recipe) => {
    if (!collection) return

    try {
      await api.collections.removeRecipe(collectionId, recipe.id)
      setCollection({
        ...collection,
        recipes: collection.recipes.filter((item) => item.recipe.id !== recipe.id),
      })
      toast.success('Removed from collection')
    } catch (error) {
      console.error('Failed to remove recipe:', error)
      toast.error('Failed to remove recipe')
    }
  }

  const handleDeleteCollection = async () => {
    setDeleting(true)
    try {
      await api.collections.delete(collectionId)
      toast.success('Collection deleted')
      navigate('/collections')
    } catch (error) {
      console.error('Failed to delete collection:', error)
      toast.error('Failed to delete collection')
    } finally {
      setDeleting(false)
    }
  }

  const handleRecipeClick = async (recipeId: number) => {
    try {
      await api.history.record(recipeId)
    } catch (error) {
      console.error('Failed to record history:', error)
    }
    navigate(`/recipe/${recipeId}`)
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <LoadingSpinner className="min-h-screen" />
      </div>
    )
  }

  if (!collection) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center bg-background">
        <span className="mb-4 text-muted-foreground">Collection not found</span>
        <button
          onClick={() => navigate('/collections')}
          className="rounded-lg bg-primary px-4 py-2 text-primary-foreground"
        >
          Go Back
        </button>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-background">
      <NavHeader />

      {/* Content */}
      <main className="px-4 py-6">
        <div className="mx-auto max-w-4xl">
          {/* Page header with title and delete button */}
          <div className="mb-4 flex items-center justify-between">
            <div>
              <h2 className="text-lg font-medium text-foreground">
                {collection.name}
              </h2>
              <p className="text-sm text-muted-foreground">
                {collection.recipes.length} recipe
                {collection.recipes.length !== 1 ? 's' : ''}
              </p>
            </div>
            <button
              onClick={() => setShowDeleteConfirm(true)}
              className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-destructive/10 hover:text-destructive"
              title="Delete collection"
            >
              <Trash2 className="h-5 w-5" />
            </button>
          </div>

      {/* Delete confirmation */}
      {showDeleteConfirm && (
        <div className="border-b border-destructive/30 bg-destructive/10 px-4 py-3">
          <div className="mx-auto flex max-w-4xl items-center justify-between">
            <p className="text-sm text-foreground">
              Delete "{collection.name}"? This cannot be undone.
            </p>
            <div className="flex gap-2">
              <button
                onClick={() => setShowDeleteConfirm(false)}
                className="rounded-lg px-3 py-1.5 text-sm text-muted-foreground hover:bg-muted hover:text-foreground"
              >
                Cancel
              </button>
              <button
                onClick={handleDeleteCollection}
                disabled={deleting}
                className="rounded-lg bg-destructive px-3 py-1.5 text-sm font-medium text-destructive-foreground transition-colors hover:bg-destructive/90 disabled:opacity-50"
              >
                {deleting ? 'Deleting...' : 'Delete'}
              </button>
            </div>
          </div>
        </div>
      )}

          {collection.recipes.length > 0 ? (
            <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 md:grid-cols-4">
              {collection.recipes.map((item) => (
                <div key={item.recipe.id} className="group relative">
                  <RecipeCard
                    recipe={item.recipe}
                    onClick={() => handleRecipeClick(item.recipe.id)}
                  />
                  {/* Remove button overlay */}
                  <button
                    onClick={(e) => {
                      e.stopPropagation()
                      handleRemoveRecipe(item.recipe)
                    }}
                    className="absolute right-2 top-2 rounded-full bg-destructive/90 p-1.5 text-destructive-foreground opacity-0 transition-opacity group-hover:opacity-100"
                    title="Remove from collection"
                  >
                    <X className="h-4 w-4" />
                  </button>
                </div>
              ))}
            </div>
          ) : (
            /* Empty state */
            <div className="flex flex-col items-center justify-center rounded-xl border-2 border-dashed border-border py-12">
              <div className="mb-4 rounded-full bg-muted p-4">
                <FolderOpen className="h-8 w-8 text-muted-foreground" />
              </div>
              <h3 className="mb-2 text-lg font-medium text-foreground">
                This collection is empty
              </h3>
              <p className="text-center text-muted-foreground">
                Add recipes from their detail pages.
              </p>
            </div>
          )}
        </div>
      </main>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { FolderPlus, Plus, X } from 'lucide-react'
import { toast } from 'sonner'
import { api, type Collection } from '../api/client'
import { cn } from '../lib/utils'
import NavHeader from '../components/NavHeader'
import { CollectionGridSkeleton } from '../components/Skeletons'

export default function Collections() {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const pendingRecipeId = searchParams.get('addRecipe') ? Number(searchParams.get('addRecipe')) : null

  const [collections, setCollections] = useState<Collection[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [newCollectionName, setNewCollectionName] = useState('')
  const [creating, setCreating] = useState(false)

  useEffect(() => {
    loadCollections()
  }, [])

  const loadCollections = async () => {
    try {
      const data = await api.collections.list()
      setCollections(data)
    } catch (error) {
      console.error('Failed to load collections:', error)
      toast.error('Failed to load collections')
    } finally {
      setLoading(false)
    }
  }

  const handleCreateCollection = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newCollectionName.trim()) return

    setCreating(true)
    try {
      const collection = await api.collections.create({
        name: newCollectionName.trim(),
      })
      setCollections([collection, ...collections])
      setNewCollectionName('')
      setShowCreateForm(false)
      toast.success('Collection created')

      // If there's a pending recipe to add, add it and navigate to collection
      if (pendingRecipeId) {
        try {
          await api.collections.addRecipe(collection.id, pendingRecipeId)
          toast.success('Recipe added to collection')
        } catch (error) {
          console.error('Failed to add recipe to collection:', error)
        }
        navigate(`/collection/${collection.id}`)
      }
    } catch (error) {
      console.error('Failed to create collection:', error)
      toast.error('Failed to create collection')
    } finally {
      setCreating(false)
    }
  }

  const handleCollectionClick = async (collectionId: number) => {
    // If there's a pending recipe, add it first
    if (pendingRecipeId) {
      try {
        await api.collections.addRecipe(collectionId, pendingRecipeId)
        toast.success('Recipe added to collection')
      } catch (error: unknown) {
        // Ignore "already in collection" error
        if (error instanceof Error && !error.message.includes('already')) {
          console.error('Failed to add recipe to collection:', error)
          toast.error('Failed to add recipe to collection')
        } else {
          toast.info('Recipe is already in this collection')
        }
      }
    }
    navigate(`/collection/${collectionId}`)
  }

  return (
    <div className="min-h-screen bg-background">
      <NavHeader />

      {/* Content */}
      <main className="px-4 py-6">
        <div className="mx-auto max-w-4xl">
          {/* Page header with title and create button */}
          <div className="mb-4 flex items-center justify-between">
            <h2 className="text-lg font-medium text-foreground">Collections</h2>
            <button
              onClick={() => setShowCreateForm(true)}
              className="flex items-center gap-2 rounded-lg bg-primary px-3 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
            >
              <Plus className="h-4 w-4" />
              New
            </button>
          </div>

          {/* Create form */}
          {showCreateForm && (
            <form
              onSubmit={handleCreateCollection}
              className="mb-6 rounded-lg border border-border bg-card p-4"
            >
              <div className="mb-4 flex items-center justify-between">
                <h2 className="font-medium text-foreground">New Collection</h2>
                <button
                  type="button"
                  onClick={() => {
                    setShowCreateForm(false)
                    setNewCollectionName('')
                  }}
                  className="rounded p-1 text-muted-foreground hover:bg-muted hover:text-foreground"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>
              <input
                type="text"
                value={newCollectionName}
                onChange={(e) => setNewCollectionName(e.target.value)}
                placeholder="Collection name"
                className="mb-3 w-full rounded-lg border border-border bg-input-background px-3 py-2 text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
                autoFocus
              />
              <div className="flex justify-end gap-2">
                <button
                  type="button"
                  onClick={() => {
                    setShowCreateForm(false)
                    setNewCollectionName('')
                  }}
                  className="rounded-lg px-4 py-2 text-sm text-muted-foreground hover:bg-muted hover:text-foreground"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={!newCollectionName.trim() || creating}
                  className="rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:opacity-50"
                >
                  {creating ? 'Creating...' : 'Create'}
                </button>
              </div>
            </form>
          )}

          {/* Pending recipe notice */}
          {pendingRecipeId && (
            <div className="mb-4 rounded-lg border border-primary/30 bg-primary/10 p-3 text-sm text-foreground">
              Select a collection or create a new one to add the recipe
            </div>
          )}

          {loading ? (
            <CollectionGridSkeleton count={8} />
          ) : collections.length > 0 ? (
            <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 md:grid-cols-4">
              {collections.map((collection) => (
                <button
                  key={collection.id}
                  onClick={() => handleCollectionClick(collection.id)}
                  className={cn(
                    'group relative overflow-hidden rounded-lg bg-card text-left shadow-sm transition-all hover:shadow-md',
                    pendingRecipeId && 'ring-2 ring-primary/20 hover:ring-primary/40'
                  )}
                >
                  {collection.cover_image ? (
                    <div className="aspect-video w-full overflow-hidden bg-muted">
                      <img
                        src={collection.cover_image}
                        alt={collection.name}
                        className="h-full w-full object-cover"
                      />
                    </div>
                  ) : (
                    <div className="flex aspect-video w-full items-center justify-center bg-muted">
                      <FolderPlus className="h-8 w-8 text-muted-foreground/50" />
                    </div>
                  )}
                  <div className="p-3">
                    <h3 className="mb-1 font-medium text-card-foreground line-clamp-1">
                      {collection.name}
                    </h3>
                    <p className="text-sm text-muted-foreground">
                      {collection.recipe_count} recipe
                      {collection.recipe_count !== 1 ? 's' : ''}
                    </p>
                  </div>
                </button>
              ))}
            </div>
          ) : (
            /* Empty state */
            <div className="flex flex-col items-center justify-center rounded-xl border-2 border-dashed border-border py-12">
              <div className="mb-4 rounded-full bg-muted p-4">
                <FolderPlus className="h-8 w-8 text-muted-foreground" />
              </div>
              <h3 className="mb-2 text-lg font-medium text-foreground">
                No collections yet
              </h3>
              <p className="mb-4 text-center text-muted-foreground">
                Create one to organize your recipes!
              </p>
              <button
                onClick={() => setShowCreateForm(true)}
                className="rounded-lg bg-primary px-4 py-2 text-primary-foreground transition-colors hover:bg-primary/90"
              >
                Create Collection
              </button>
            </div>
          )}
        </div>
      </main>
    </div>
  )
}

import { useState, useEffect } from 'react'
