          )}
        </div>
      </main>
    </div>
  )
}

import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { api } from '../api/client'
import {
  prepareAuthenticationOptions,
  serializeAuthenticationCredential,
} from '../lib/webauthn'
import { useAuth } from '../contexts/AuthContext'

export default function PasskeyLogin() {
  const navigate = useNavigate()
  const { refreshSession } = useAuth()
  const [error, setError] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const webauthnSupported = typeof window !== 'undefined' && !!window.PublicKeyCredential

  async function handleLogin() {
    setError('')
    setSubmitting(true)

    try {
      const options = await api.passkey.loginOptions()

      if (options && 'no_credentials' in options) {
        setError('No accounts exist yet. Create an account first.')
        return
      }

      const publicKeyOptions = prepareAuthenticationOptions(options)

      const credential = await navigator.credentials.get({
        publicKey: publicKeyOptions,
      })

      if (!credential) {
        setError('Sign in was cancelled.')
        return
      }

      await api.passkey.loginVerify(
        serializeAuthenticationCredential(credential as PublicKeyCredential)
      )

      await refreshSession()
      navigate('/home')
    } catch (err) {
      if (err instanceof DOMException && err.name === 'NotAllowedError') {
        setError('Sign in was cancelled.')
      } else {
        setError(err instanceof Error ? err.message : 'Sign in failed')
      }
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-background p-4">
      <div className="w-full max-w-sm space-y-6">
        <div className="text-center">
          <h1 className="text-3xl font-bold text-foreground">Cookie</h1>
          <p className="mt-1 text-sm text-muted-foreground">Sign in with your passkey</p>
        </div>

        {error && (
          <div role="alert" className="rounded-md bg-red-50 p-3 text-sm text-red-800 dark:bg-red-900/20 dark:text-red-300">
            {error}
          </div>
        )}

        <div className="space-y-4">
          {webauthnSupported ? (
            <button
              onClick={handleLogin}
              disabled={submitting}
              className="w-full rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground shadow-sm hover:bg-primary/90 disabled:opacity-50"
            >
              {submitting ? 'Signing in...' : 'Sign In'}
            </button>
          ) : (
            <p className="text-center text-sm text-muted-foreground">
              Your browser does not support passkeys. Please use a modern browser or pair this device
              using a code from another device.
            </p>
          )}
        </div>

        <div className="text-center text-sm text-muted-foreground">
          <p>
            Don't have an account?{' '}
            <Link to="/register" className="font-medium text-primary hover:underline">
              Create Account
            </Link>
          </p>
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { api } from '../api/client'
import type { PasskeyCredential } from '../api/types'
import {
  prepareRegistrationOptions,
  serializeRegistrationCredential,
} from '../lib/webauthn'

export default function PasskeyManage() {
  const navigate = useNavigate()
  const [credentials, setCredentials] = useState<PasskeyCredential[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [adding, setAdding] = useState(false)

  const loadCredentials = useCallback(async () => {
    try {
      const data = await api.passkey.listCredentials()
      setCredentials(data.credentials)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load passkeys')
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    loadCredentials()
  }, [loadCredentials])

  async function handleAdd() {
    setError('')
    setAdding(true)

    try {
      const options = await api.passkey.addCredentialOptions()
      const publicKeyOptions = prepareRegistrationOptions(options)

      const credential = await navigator.credentials.create({
        publicKey: publicKeyOptions,
      })

      if (!credential) {
        setError('Adding passkey was cancelled.')
        return
      }

      await api.passkey.addCredentialVerify(
        serializeRegistrationCredential(credential as PublicKeyCredential)
      )

      await loadCredentials()
    } catch (err) {
      if (err instanceof DOMException && err.name === 'NotAllowedError') {
        setError('Adding passkey was cancelled.')
      } else {
        setError(err instanceof Error ? err.message : 'Failed to add passkey')
      }
    } finally {
      setAdding(false)
    }
  }

  async function handleDelete(credentialId: number) {
    if (!window.confirm('Are you sure you want to delete this passkey? This cannot be undone.')) {
      return
    }
    setError('')
    try {
      await api.passkey.deleteCredential(credentialId)
      await loadCredentials()
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to delete passkey')
    }
  }

  function formatDate(dateStr: string | null): string {
    if (!dateStr) return 'Never'
    return new Date(dateStr).toLocaleDateString(undefined, {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    })
  }

  if (loading) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="text-muted-foreground">Loading...</div>
      </div>
    )
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-background p-4">
      <div className="w-full max-w-md space-y-6">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-foreground">Manage Passkeys</h1>
          <p className="mt-1 text-sm text-muted-foreground">
            {credentials.length} passkey{credentials.length !== 1 ? 's' : ''} registered
          </p>
        </div>

        {error && (
          <div role="alert" className="rounded-md bg-red-50 p-3 text-sm text-red-800 dark:bg-red-900/20 dark:text-red-300">
            {error}
          </div>
        )}

        <div className="space-y-3">
          {credentials.map((cred) => (
            <div
              key={cred.id}
              className="flex items-center justify-between rounded-lg border border-input bg-background p-4"
            >
              <div>
                <div className="text-sm font-medium text-foreground">
                  Passkey #{cred.id}
                </div>
                <div className="text-xs text-muted-foreground">
                  Added {formatDate(cred.created_at)}
                </div>
                <div className="text-xs text-muted-foreground">
                  Last used: {formatDate(cred.last_used_at)}
                </div>
              </div>
              {cred.is_deletable && (
                <button
                  onClick={() => handleDelete(cred.id)}
                  className="rounded-md px-3 py-1 text-sm text-red-600 hover:bg-red-50 dark:text-red-400 dark:hover:bg-red-900/20"
                >
                  Delete
                </button>
              )}
            </div>
          ))}
        </div>

        <button
          onClick={handleAdd}
          disabled={adding}
          className="w-full rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground shadow-sm hover:bg-primary/90 disabled:opacity-50"
        >
          {adding ? 'Adding passkey...' : 'Add Passkey'}
        </button>

        <div className="text-center">
          <button
            onClick={() => navigate(-1)}
            className="text-sm text-muted-foreground hover:text-foreground"
          >
            Go back
          </button>
        </div>
      </div>
    </div>
  )
}

