import { useState, useCallback, useEffect } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { X, ChevronLeft, ChevronRight } from 'lucide-react'
import { toast } from 'sonner'
import { api, type RecipeDetail } from '../api/client'
import { useTimers } from '../hooks/useTimers'
import { useWakeLock } from '../hooks/useWakeLock'
import TimerPanel from '../components/TimerPanel'
import { cn } from '../lib/utils'
import { unlockAudio, playTimerAlert } from '../lib/audio'
import { LoadingSpinner } from '../components/Skeletons'

export default function PlayMode() {
  const navigate = useNavigate()
  const { id } = useParams<{ id: string }>()
  const recipeId = Number(id)

  const [recipe, setRecipe] = useState<RecipeDetail | null>(null)
  const [loading, setLoading] = useState(true)
  const [currentStep, setCurrentStep] = useState(0)
  const [aiAvailable, setAiAvailable] = useState(false)

  // Fetch recipe data on mount
  useEffect(() => {
    if (recipeId) {
      loadData()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- loadData is stable, only re-run when recipeId changes
  }, [recipeId])

  const loadData = async () => {
    try {
      const [recipeData, aiStatus] = await Promise.all([
        api.recipes.get(recipeId),
        api.ai.status(),
      ])
      setRecipe(recipeData)
      setAiAvailable(aiStatus.available)
    } catch (error) {
      console.error('Failed to load recipe:', error)
      toast.error('Failed to load recipe')
      navigate(-1)
    } finally {
      setLoading(false)
    }
  }

  // Get instructions array
  const instructions = recipe
    ? recipe.instructions.length > 0
      ? recipe.instructions
      : recipe.instructions_text
        ? recipe.instructions_text.split('\n').filter((s) => s.trim())
        : []
    : []

  const totalSteps = instructions.length

  // Timer completion handler
  const handleTimerComplete = useCallback(
    (timer: { label: string }) => {
      // Play audio alert
      playTimerAlert()

      // Show toast notification
      toast.success(`Timer complete: ${timer.label}`, {
        duration: 10000,
      })

      // Show browser notification (may include system sound)
      try {
        if ('Notification' in window && Notification.permission === 'granted') {
          new Notification('Timer Complete!', {
            body: timer.label,
            icon: '/favicon.ico',
          })
        }
      } catch {
        // Notification not supported or blocked
      }
    },
    []
  )

  const timers = useTimers(handleTimerComplete)

  // Keep screen awake during Play Mode
  useWakeLock()

  // Request notification permission and unlock audio on mount
  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission()
    }
    // Unlock audio for iOS (requires user interaction context)
    // This works because entering Play Mode requires a button click
    unlockAudio()
  }, [])

  // eslint-disable-next-line security/detect-object-injection -- currentStep is controlled state (number), not user input
  const currentInstruction = instructions[currentStep] || ''
  const progress = totalSteps > 0 ? ((currentStep + 1) / totalSteps) * 100 : 0

  const handlePrevious = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1)
    }
  }

  const handleNext = () => {
    if (currentStep < totalSteps - 1) {
      setCurrentStep(currentStep + 1)
    }
  }

  const handleExit = () => {
    navigate(-1)
  }

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
        handlePrevious()
      } else if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
        handleNext()
      } else if (e.key === 'Escape') {
        handleExit()
      }
    }

    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
    // eslint-disable-next-line react-hooks/exhaustive-deps -- handlers use currentStep/totalSteps from closure, re-bind when they change
  }, [currentStep, totalSteps])

  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <LoadingSpinner className="min-h-screen" />
      </div>
    )
  }

  if (!recipe) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center bg-background p-4">
        <p className="mb-4 text-center text-muted-foreground">
          Recipe not found.
        </p>
        <button
          onClick={handleExit}
          className="rounded-lg bg-primary px-4 py-2 text-primary-foreground"
        >
          Go Back
        </button>
      </div>
    )
  }

  if (totalSteps === 0) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center bg-background p-4">
        <p className="mb-4 text-center text-muted-foreground">
          No instructions available for this recipe.
        </p>
        <button
          onClick={handleExit}
          className="rounded-lg bg-primary px-4 py-2 text-primary-foreground"
        >
          Exit
        </button>
      </div>
    )
  }

  return (
    <div className="flex min-h-screen flex-col bg-background">
      {/* Header with progress */}
      <div className="relative border-b border-border">
        {/* Progress bar */}
        <div className="h-1 bg-muted">
          <div
            className="h-full bg-primary transition-all duration-300"
            style={{ width: `${progress}%` }}
          />
        </div>

        {/* Header content */}
        <div className="flex items-center justify-between px-4 py-3">
          <div className="flex-1">
            <h1 className="line-clamp-1 text-sm font-medium text-foreground">
              {recipe.title}
            </h1>
            <p className="text-xs text-muted-foreground">
              Step {currentStep + 1} of {totalSteps}
            </p>
          </div>

          <button
            onClick={handleExit}
            className="rounded-full bg-muted p-2 text-muted-foreground transition-colors hover:bg-muted/80"
            aria-label="Exit play mode"
          >
            <X className="h-5 w-5" />
          </button>
        </div>
      </div>

      {/* Main content area */}
      <div className="flex flex-1 flex-col">
        {/* Instruction display */}
        <div className="flex flex-1 items-center justify-center p-6" style={{ maxHeight: '60vh' }}>
          <div className="max-w-2xl text-center">
            {/* Step number */}
            <div className="mx-auto mb-6 flex h-12 w-12 items-center justify-center rounded-full bg-primary text-xl font-bold text-primary-foreground">
              {currentStep + 1}
            </div>

            {/* Instruction text */}
            <p className="text-xl leading-relaxed text-foreground sm:text-2xl">
              {currentInstruction}
            </p>
          </div>
        </div>

        {/* Navigation buttons */}
        <div className="flex items-center justify-between border-t border-border px-4 py-4">
          <button
            onClick={handlePrevious}
            disabled={currentStep === 0}
            className={cn(
              'flex items-center gap-2 rounded-lg px-4 py-3 text-sm font-medium transition-colors',
              currentStep === 0
                ? 'text-muted-foreground opacity-50'
                : 'bg-muted text-foreground hover:bg-muted/80'
            )}
          >
            <ChevronLeft className="h-5 w-5" />
            Previous
          </button>

          {/* Step indicators */}
          <div className="hidden gap-1.5 sm:flex">
            {instructions.map((_, idx) => (
              <button
                key={idx}
                onClick={() => setCurrentStep(idx)}
                className={cn(
                  'h-2 w-2 rounded-full transition-all',
                  idx === currentStep
                    ? 'w-6 bg-primary'
                    : idx < currentStep
                      ? 'bg-primary/50'
                      : 'bg-muted'
                )}
                aria-label={`Go to step ${idx + 1}`}
              />
            ))}
          </div>

          <button
            onClick={handleNext}
            disabled={currentStep === totalSteps - 1}
            className={cn(
              'flex items-center gap-2 rounded-lg px-4 py-3 text-sm font-medium transition-colors',
              currentStep === totalSteps - 1
                ? 'text-muted-foreground opacity-50'
                : 'bg-primary text-primary-foreground hover:bg-primary/90'
            )}
          >
            Next
            <ChevronRight className="h-5 w-5" />
          </button>
        </div>

        {/* Timer panel */}
        <TimerPanel timers={timers} instructionText={currentInstruction} aiAvailable={aiAvailable} />
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { Plus } from 'lucide-react'
import { toast } from 'sonner'
import { api, type Profile, type ProfileInput } from '../api/client'
import { useProfile } from '../contexts/ProfileContext'
import { cn } from '../lib/utils'

const PROFILE_COLORS = [
  '#d97850',
  '#8fae6f',
  '#6b9dad',
  '#9d80b8',
  '#d16b6b',
  '#e6a05f',
  '#6bb8a5',
  '#c77a9e',
  '#7d9e6f',
  '#5b8abf',
]

export default function ProfileSelector() {
  const navigate = useNavigate()
  const { selectProfile } = useProfile()
  const [profiles, setProfiles] = useState<Profile[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [newName, setNewName] = useState('')
  const [selectedColor, setSelectedColor] = useState(PROFILE_COLORS[0])
  const [creating, setCreating] = useState(false)

  useEffect(() => {
    loadProfiles()
  }, [])

  const loadProfiles = async () => {
    try {
      const data = await api.profiles.list()
      setProfiles(data)
    } catch (error) {
      console.error('Failed to load profiles:', error)
      toast.error('Failed to load profiles')
    } finally {
      setLoading(false)
    }
  }

  const handleProfileSelect = async (profile: Profile) => {
    try {
      await selectProfile(profile)
      navigate('/home')
    } catch (error) {
      console.error('Failed to select profile:', error)
      toast.error('Failed to select profile')
    }
  }

  const handleCreateProfile = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newName.trim()) return

    setCreating(true)
    try {
      const data: ProfileInput = {
        name: newName.trim(),
        avatar_color: selectedColor,
        theme: 'light',
        unit_preference: 'metric',
      }
      const profile = await api.profiles.create(data)
      setProfiles([...profiles, profile])
      await selectProfile(profile)
      toast.success(`Welcome, ${profile.name}!`)
      navigate('/home')
    } catch (error) {
      console.error('Failed to create profile:', error)
      toast.error('Failed to create profile')
    } finally {
      setCreating(false)
    }
  }

  const getInitial = (name: string) => {
    return name.charAt(0).toUpperCase()
  }

  if (loading) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="text-muted-foreground">Loading...</div>
      </div>
    )
  }

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-background px-4">
      <div className="w-full max-w-md text-center">
        {/* Title */}
        <h1 className="mb-2 text-4xl font-medium text-primary">Cookie</h1>
        <p className="mb-10 text-muted-foreground">Who's cooking today?</p>

        {/* Profile grid */}
        <div className="mb-8 flex flex-wrap justify-center gap-6">
          {profiles.map((profile) => (
            <button
              key={profile.id}
              onClick={() => handleProfileSelect(profile)}
              className="group flex flex-col items-center gap-2"
            >
              <div
                className="flex h-20 w-20 items-center justify-center rounded-full text-2xl font-medium text-white transition-transform group-hover:scale-105"
                style={{ backgroundColor: profile.avatar_color }}
              >
                {getInitial(profile.name)}
              </div>
              <span className="text-sm text-foreground">{profile.name}</span>
            </button>
          ))}

          {/* Add profile button */}
          <button
            onClick={() => setShowCreateForm(true)}
            className="group flex flex-col items-center gap-2"
          >
            <div className="flex h-20 w-20 items-center justify-center rounded-full border-2 border-dashed border-muted-foreground/40 transition-colors group-hover:border-primary">
              <Plus className="h-8 w-8 text-muted-foreground/60 group-hover:text-primary" />
            </div>
            <span className="text-sm text-muted-foreground">Add Profile</span>
          </button>
        </div>

        {/* Create profile form */}
        {showCreateForm && (
          <div className="rounded-lg border border-border bg-card p-6 shadow-sm">
            <h2 className="mb-4 text-lg font-medium text-card-foreground">
              Create Profile
            </h2>
            <form onSubmit={handleCreateProfile}>
              <div className="mb-4">
                <input
                  type="text"
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="Enter your name"
                  className="w-full rounded-lg border border-border bg-input-background px-4 py-3 text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
                  autoFocus
                  maxLength={20}
                />
              </div>

              {/* Color picker */}
              <div className="mb-6">
                <label className="mb-2 block text-sm text-muted-foreground">
                  Choose a color
                </label>
                <div className="flex flex-wrap justify-center gap-2">
                  {PROFILE_COLORS.map((color) => (
                    <button
                      key={color}
                      type="button"
                      onClick={() => setSelectedColor(color)}
                      className={cn(
                        'h-10 w-10 rounded-full transition-transform hover:scale-110',
                        selectedColor === color && 'ring-2 ring-ring ring-offset-2 ring-offset-card'
                      )}
                      style={{ backgroundColor: color }}
                    />
                  ))}
                </div>
              </div>

              {/* Buttons */}
              <div className="flex gap-3">
                <button
                  type="button"
                  onClick={() => {
                    setShowCreateForm(false)
                    setNewName('')
                    setSelectedColor(PROFILE_COLORS[0])
                  }}
                  className="flex-1 rounded-lg border border-border bg-secondary px-4 py-2.5 text-secondary-foreground transition-colors hover:bg-muted"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={!newName.trim() || creating}
                  className="flex-1 rounded-lg bg-primary px-4 py-2.5 text-primary-foreground transition-colors hover:bg-primary/90 disabled:opacity-50"
                >
                  {creating ? 'Creating...' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        )}
      </div>
    </div>
  )
}

