type Tab = 'general' | 'prompts' | 'sources' | 'selectors' | 'users' | 'danger' | 'account'

function useIsAdmin(): boolean {
  const mode = useMode()
  const auth = useAuth()
  if (mode === 'passkey') {
    return auth.isAdmin
  }
  return true
}

