          api.ai.status(),
          api.ai.prompts.list(),
          api.ai.models(),
          api.sources.list(),
          api.profiles.list(),
        ])
      setAiStatus(statusData)
      setPrompts(promptsData)
      setModels(modelsData)
      setSources(sourcesData)
      setProfiles(profilesData)
