          ) : activeTab === 'selectors' ? (
            <SettingsSelectors sources={sources} onSourcesChange={setSources} />
          ) : activeTab === 'users' ? (
            <SettingsUsers
              profiles={profiles}
              currentProfileId={currentProfileId}
              onProfilesChange={setProfiles}
            />
          ) : activeTab === 'danger' ? (
            <SettingsDanger />
          ) : null}
        </div>
      </main>
    </div>
  )
}

import { type ReactNode, useState, useCallback } from 'react'
import {
  Star,
  Clock,
  ChevronDown,
  ChevronUp,
  Minus,
  Plus,
  GitCompareArrows,
} from 'lucide-react'
import { useNavigate } from 'react-router-dom'
import { type RecipeDetail, type ScaleResponse } from '../../api/client'
import { cn } from '../../lib/utils'
import { formatTime } from '../../lib/formatting'

interface RecipeHeaderProps {
  recipe: RecipeDetail
  imageUrl: string | null | undefined
  metaExpanded: boolean
  setMetaExpanded: (expanded: boolean) => void
  canShowServingAdjustment: boolean
  servings: number | null
  scaledData: ScaleResponse | null
  scalingLoading: boolean
  onServingChange: (delta: number) => void
  children?: ReactNode
}

export default function RecipeHeader({
  recipe,
  imageUrl,
  metaExpanded,
  setMetaExpanded,
  canShowServingAdjustment,
  servings,
  scaledData,
  scalingLoading,
  onServingChange,
  children,
}: RecipeHeaderProps) {
  const navigate = useNavigate()
  const [imgError, setImgError] = useState(false)

  const handleImgError = useCallback(() => {
    setImgError(true)
  }, [])

  return (
    <>
      {/* Hero Image */}
      <div className="relative h-64 sm:h-80">
        {imageUrl && !imgError ? (
          <img
            src={imageUrl}
            alt={recipe.title}
            loading="lazy"
            onError={handleImgError}
            className="h-full w-full object-cover"
          />
        ) : (
          <div className="flex h-full w-full items-center justify-center bg-gradient-to-br from-muted to-muted/60">
            <span className="px-4 text-center text-lg font-medium text-muted-foreground">
              {recipe.title}
            </span>
          </div>
        )}

        {/* Gradient overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/30 to-transparent" />

        {/* Title and rating overlay */}
        <div className="absolute bottom-4 left-4 right-4">
          <h1 className="mb-2 text-xl font-medium text-white drop-shadow-lg sm:text-2xl">
            {recipe.title}
          </h1>
          <div className="flex items-center gap-3 text-sm text-white/90">
            {recipe.rating && (
              <span className="flex items-center gap-1">
                <Star className="h-4 w-4 fill-star text-star" />
                {recipe.rating.toFixed(1)}
                {recipe.rating_count && (
                  <span className="text-white/70">
                    ({recipe.rating_count})
                  </span>
                )}
              </span>
            )}
            <span>{recipe.host}</span>
          </div>
        </div>

        {/* Action buttons overlay */}
        {children}
      </div>

      {/* Meta info (collapsible) */}
      <div className="border-b border-border">
        <button
          onClick={() => setMetaExpanded(!metaExpanded)}
          className="flex w-full items-center justify-between px-4 py-3 text-left"
        >
          <span className="text-sm font-medium text-foreground">
            Recipe Details
          </span>
          {metaExpanded ? (
            <ChevronUp className="h-5 w-5 text-muted-foreground" />
          ) : (
            <ChevronDown className="h-5 w-5 text-muted-foreground" />
          )}
        </button>

        {metaExpanded && (
          <div className="flex flex-wrap gap-4 px-4 pb-4">
            <TimeDisplay
              label="Prep"
              time={recipe.prep_time}
              adjustedTime={scaledData?.prep_time_adjusted}
            />
            <TimeDisplay
              label="Cook"
              time={recipe.cook_time}
              adjustedTime={scaledData?.cook_time_adjusted}
            />
            <TimeDisplay
              label="Total"
              time={recipe.total_time}
              adjustedTime={scaledData?.total_time_adjusted}
            />

            {/* Servings adjuster - only show if AI available and servings present */}
            {canShowServingAdjustment && servings && (
              <div className="flex items-center gap-2 text-sm">
                <span className="text-muted-foreground">Servings:</span>
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => onServingChange(-1)}
                    disabled={servings <= 1 || scalingLoading}
                    className="rounded-md bg-muted p-1 text-foreground transition-colors hover:bg-muted/80 disabled:opacity-50"
                  >
                    <Minus className="h-4 w-4" />
                  </button>
                  <span className="w-8 text-center font-medium text-foreground">
                    {scalingLoading ? '...' : servings}
                  </span>
                  <button
                    onClick={() => onServingChange(1)}
                    disabled={scalingLoading}
                    className="rounded-md bg-muted p-1 text-foreground transition-colors hover:bg-muted/80 disabled:opacity-50"
                  >
                    <Plus className="h-4 w-4" />
                  </button>
                </div>
                {scaledData && servings !== recipe?.servings && (
                  <span className="text-xs text-muted-foreground">
                    (scaled from {recipe?.servings})
                  </span>
                )}
              </div>
            )}

            {/* Show static servings if AI not available */}
            {!canShowServingAdjustment && recipe.servings && (
              <div className="flex items-center gap-2 text-sm">
                <span className="text-muted-foreground">Servings:</span>
                <span className="text-foreground">{recipe.servings}</span>
              </div>
            )}

            {/* Yields (if different from servings) */}
            {recipe.yields && !recipe.servings && (
              <div className="flex items-center gap-2 text-sm">
                <span className="text-muted-foreground">Yields:</span>
                <span className="text-foreground">{recipe.yields}</span>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Linked Recipes Navigation */}
      {recipe.linked_recipes && recipe.linked_recipes.length > 0 && (
        <div className="border-b border-border px-4 py-3">
          <div className="flex items-center gap-2 text-sm">
            <GitCompareArrows className="h-4 w-4 text-muted-foreground" />
            <span className="text-muted-foreground">Linked recipes:</span>
            <div className="flex flex-wrap gap-2">
              {recipe.linked_recipes.map((linked) => (
                <button
                  key={linked.id}
                  onClick={() => navigate(`/recipe/${linked.id}`)}
                  className="inline-flex items-center gap-1 rounded-full bg-muted px-3 py-1 text-xs font-medium text-foreground transition-colors hover:bg-muted/80"
                >
                  <span
                    className={cn(
                      'h-1.5 w-1.5 rounded-full',
                      linked.relationship === 'original'
                        ? 'bg-primary'
                        : linked.relationship === 'remix'
                          ? 'bg-accent'
                          : 'bg-muted-foreground'
                    )}
                  />
                  {linked.title}
                  <span className="text-muted-foreground">
                    ({linked.relationship})
                  </span>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}
    </>
  )
}

function TimeDisplay({
  label,
  time,
  adjustedTime,
}: {
  label: string
  time: number | null
  adjustedTime: number | null | undefined
}) {
  if (!time) return null

  return (
    <div className="flex items-center gap-2 text-sm">
      <Clock className="h-4 w-4 text-muted-foreground" />
      <span className="text-muted-foreground">{label}:</span>
      <span className="text-foreground">
        {adjustedTime && adjustedTime !== time ? (
          <>
            {formatTime(adjustedTime)}
            <span className="ml-1 text-muted-foreground">
              (was {formatTime(time)})
            </span>
          </>
        ) : (
          formatTime(adjustedTime ?? time)
        )}
      </span>
    </div>
  )
}

import { type RecipeDetail, type ScaleResponse } from '../../api/client'

interface RecipeIngredientsProps {
  recipe: RecipeDetail
  scaledData: ScaleResponse | null
}

export default function RecipeIngredients({
  recipe,
  scaledData,
}: RecipeIngredientsProps) {
  // Use scaled ingredients if available, otherwise use recipe ingredients
  const ingredients = scaledData?.ingredients || recipe.ingredients

  // Use ingredient_groups if available and not scaled, otherwise flat ingredients list
  const hasGroups = recipe.ingredient_groups.length > 0 && !scaledData

  if (hasGroups) {
    return (
      <div className="space-y-6">
        {recipe.ingredient_groups.map((group, groupIndex) => (
          <div key={groupIndex}>
            {group.purpose && (
              <h3 className="mb-3 font-medium text-foreground">
                {group.purpose}
              </h3>
            )}
            <ol className="space-y-2">
              {group.ingredients.map((ingredient, index) => (
                <li
                  key={index}
                  className="flex items-start gap-3 text-foreground"
                >
                  <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-primary text-sm font-medium text-primary-foreground">
                    {index + 1}
                  </span>
                  <span>{ingredient}</span>
                </li>
              ))}
            </ol>
          </div>
        ))}
      </div>
    )
  }

  return (
    <ol className="space-y-2">
      {ingredients.map((ingredient, index) => (
        <li key={index} className="flex items-start gap-3 text-foreground">
          <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-primary text-sm font-medium text-primary-foreground">
            {index + 1}
          </span>
          <span>{ingredient}</span>
        </li>
      ))}
    </ol>
  )
}

import { Sparkles } from 'lucide-react'
import { type RecipeDetail, type ScaleResponse } from '../../api/client'
import { cn, formatNutritionKey } from '../../lib/utils'
import type { Tab } from '../../hooks/useRecipeDetail'
import RecipeIngredients from './RecipeIngredients'
import RecipeInstructions from './RecipeInstructions'

interface RecipeTabsProps {
  recipe: RecipeDetail
  activeTab: Tab
  setActiveTab: (tab: Tab) => void
  scaledData: ScaleResponse | null
  tips: string[]
  tipsLoading: boolean
  tipsPolling: boolean
  aiAvailable: boolean
  onGenerateTips: (regenerate: boolean) => void
}

export default function RecipeTabs({
  recipe,
  activeTab,
  setActiveTab,
  scaledData,
  tips,
  tipsLoading,
  tipsPolling,
  aiAvailable,
  onGenerateTips,
}: RecipeTabsProps) {
  const tabItems: { key: Tab; label: string }[] = [
    { key: 'ingredients', label: 'Ingredients' },
    { key: 'instructions', label: 'Instructions' },
    { key: 'nutrition', label: 'Nutrition' },
    ...(aiAvailable ? [{ key: 'tips' as const, label: 'Tips' }] : []),
  ]

  return (
    <>
      {/* Tab bar */}
      <div className="border-b border-border">
        <div className="flex px-4">
          {tabItems.map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setActiveTab(key)}
              className={cn(
                'border-b-2 px-4 py-3 text-sm font-medium transition-colors',
                activeTab === key
                  ? 'border-primary text-primary'
                  : 'border-transparent text-muted-foreground hover:text-foreground'
              )}
            >
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* Tab content */}
      <div className="px-4 py-6">
        {activeTab === 'ingredients' && (
          <RecipeIngredients recipe={recipe} scaledData={scaledData} />
        )}
        {activeTab === 'instructions' && (
          <RecipeInstructions recipe={recipe} scaledData={scaledData} />
        )}
        {activeTab === 'nutrition' && (
          <NutritionTab recipe={recipe} />
        )}
        {activeTab === 'tips' && (
          <TipsTab
            tips={tips}
            scalingNotes={scaledData?.notes || []}
            aiAvailable={aiAvailable}
            loading={tipsLoading}
            polling={tipsPolling}
            onGenerateTips={onGenerateTips}
          />
        )}
      </div>
    </>
  )
}

function NutritionTab({ recipe }: { recipe: RecipeDetail }) {
  const nutritionEntries = Object.entries(recipe.nutrition || {})

  if (nutritionEntries.length === 0) {
    return (
      <p className="text-muted-foreground">
        No nutrition information available for this recipe.
      </p>
    )
  }

  return (
    <div>
      {recipe.servings && (
        <p className="mb-4 text-sm text-muted-foreground">
          Per serving (recipe makes {recipe.servings})
        </p>
      )}
      <div className="grid grid-cols-2 gap-3 sm:grid-cols-3">
        {nutritionEntries.map(([key, value]) => (
          <div
            key={key}
            className="rounded-lg bg-muted/50 p-3"
          >
            <span className="block text-sm text-muted-foreground">
              {formatNutritionKey(key)}
            </span>
            <span className="text-lg font-medium text-foreground">{value}</span>
          </div>
        ))}
      </div>
    </div>
  )
}

function TipsTab({
  tips,
  scalingNotes,
  aiAvailable,
  loading,
  polling,
  onGenerateTips,
}: {
  tips: string[]
  scalingNotes: string[]
  aiAvailable?: boolean
  loading: boolean
  polling: boolean
  onGenerateTips: (regenerate: boolean) => void
}) {
  if (loading) {
    return (
      <div className="text-center">
        <Sparkles className="mx-auto mb-3 h-8 w-8 animate-pulse text-primary" />
        <p className="text-foreground">Generating cooking tips...</p>
      </div>
    )
  }

  const hasTips = tips.length > 0
  const hasContent = hasTips || scalingNotes.length > 0

  if (!hasContent && polling) {
    return (
      <div className="text-center">
        <Sparkles className="mx-auto mb-3 h-8 w-8 animate-pulse text-primary" />
        <p className="text-foreground">Generating cooking tips...</p>
        <p className="mt-2 text-sm text-muted-foreground">
          Tips are being generated in the background
        </p>
      </div>
    )
  }

  if (!hasContent) {
    return (
      <div className="text-center">
        <Sparkles className="mx-auto mb-3 h-8 w-8 text-muted-foreground" />
        <p className="mb-2 text-foreground">No cooking tips yet</p>
        {aiAvailable ? (
          <button
            onClick={() => onGenerateTips(false)}
            className="mt-4 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
          >
            Generate Tips
          </button>
        ) : (
          <p className="text-sm text-muted-foreground">
            Configure an API key in settings to enable AI-generated tips
          </p>
        )}
      </div>
    )
  }

  return (
    <div className="space-y-4">
      {scalingNotes.length > 0 && (
        <div className="rounded-lg bg-accent/10 p-3">
          <h4 className="mb-2 flex items-center gap-2 text-sm font-medium text-foreground">
            <Sparkles className="h-4 w-4 text-accent" />
            Scaling Notes
          </h4>
          <ul className="space-y-1 text-sm text-muted-foreground">
            {scalingNotes.map((note, index) => (
              <li key={index}>• {note}</li>
            ))}
          </ul>
        </div>
      )}

      {hasTips && (
        <ol className="space-y-3">
          {tips.map((tip, index) => (
            <li key={index} className="flex items-start gap-3">
              <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-accent text-xs font-medium text-accent-foreground">
                {index + 1}
              </span>
              <p className="text-foreground">{tip}</p>
            </li>
          ))}
        </ol>
      )}

      {aiAvailable && (
        <div className="text-center pt-4">
          <button
            onClick={() => onGenerateTips(hasTips)}
            className="rounded-lg bg-muted px-4 py-2 text-sm font-medium text-muted-foreground transition-colors hover:bg-muted/80 hover:text-foreground"
          >
            {hasTips ? 'Regenerate Tips' : 'Generate Tips'}
          </button>
        </div>
      )}
    </div>
  )
}

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import AddToCollectionDropdown from '../components/AddToCollectionDropdown'
import { api } from '../api/client'

// Mock the API
vi.mock('../api/client', () => ({
  api: {
    collections: {
      list: vi.fn(),
      addRecipe: vi.fn(),
    },
  },
}))

// Mock sonner toast
vi.mock('sonner', () => ({
  toast: {
    success: vi.fn(),
    error: vi.fn(),
    info: vi.fn(),
  },
}))

describe('AddToCollectionDropdown', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('renders the folder button', () => {
    render(
      <AddToCollectionDropdown recipeId={1} onCreateNew={vi.fn()} />
    )
    expect(screen.getByTitle('Add to collection')).toBeInTheDocument()
  })

  it('opens dropdown when button is clicked', async () => {
    vi.mocked(api.collections.list).mockResolvedValue([])

    render(
      <AddToCollectionDropdown recipeId={1} onCreateNew={vi.fn()} />
    )

    fireEvent.click(screen.getByTitle('Add to collection'))

    await waitFor(() => {
      expect(screen.getByText('Add to Collection')).toBeInTheDocument()
    })
  })

  it('shows loading state while fetching collections', async () => {
    vi.mocked(api.collections.list).mockImplementation(
      () => new Promise(() => {})
    )

    render(
      <AddToCollectionDropdown recipeId={1} onCreateNew={vi.fn()} />
    )

    fireEvent.click(screen.getByTitle('Add to collection'))

    await waitFor(() => {
      expect(screen.getByText('Loading...')).toBeInTheDocument()
    })
  })

  it('displays collections when loaded', async () => {
    vi.mocked(api.collections.list).mockResolvedValue([
      { id: 1, name: 'Favorites', description: '', recipe_count: 0, created_at: '', updated_at: '' },
      { id: 2, name: 'Quick Meals', description: '', recipe_count: 0, created_at: '', updated_at: '' },
    ])

    render(
      <AddToCollectionDropdown recipeId={1} onCreateNew={vi.fn()} />
    )

    fireEvent.click(screen.getByTitle('Add to collection'))

    await waitFor(() => {
      expect(screen.getByText('Favorites')).toBeInTheDocument()
      expect(screen.getByText('Quick Meals')).toBeInTheDocument()
    })
  })

  it('shows empty message when no collections exist', async () => {
    vi.mocked(api.collections.list).mockResolvedValue([])

    render(
      <AddToCollectionDropdown recipeId={1} onCreateNew={vi.fn()} />
    )

    fireEvent.click(screen.getByTitle('Add to collection'))

    await waitFor(() => {
      expect(screen.getByText('No collections yet')).toBeInTheDocument()
    })
  })

  it('shows Create New Collection option', async () => {
    vi.mocked(api.collections.list).mockResolvedValue([])

    render(
      <AddToCollectionDropdown recipeId={1} onCreateNew={vi.fn()} />
    )

    fireEvent.click(screen.getByTitle('Add to collection'))

    await waitFor(() => {
      expect(screen.getByText('Create New Collection')).toBeInTheDocument()
    })
  })

  it('calls onCreateNew when Create New Collection is clicked', async () => {
    vi.mocked(api.collections.list).mockResolvedValue([])

    const handleCreateNew = vi.fn()
    render(
      <AddToCollectionDropdown recipeId={1} onCreateNew={handleCreateNew} />
    )

    fireEvent.click(screen.getByTitle('Add to collection'))

    await waitFor(() => {
      expect(screen.getByText('Create New Collection')).toBeInTheDocument()
    })

    fireEvent.click(screen.getByText('Create New Collection'))

    expect(handleCreateNew).toHaveBeenCalled()
  })

  it('adds recipe to collection when collection is clicked', async () => {
    vi.mocked(api.collections.list).mockResolvedValue([
      { id: 1, name: 'Favorites', description: '', recipe_count: 0, created_at: '', updated_at: '' },
    ])
    vi.mocked(api.collections.addRecipe).mockResolvedValue({} as never)

    render(
      <AddToCollectionDropdown recipeId={42} onCreateNew={vi.fn()} />
    )

    fireEvent.click(screen.getByTitle('Add to collection'))

    await waitFor(() => {
      expect(screen.getByText('Favorites')).toBeInTheDocument()
    })

    fireEvent.click(screen.getByText('Favorites'))

    await waitFor(() => {
      expect(api.collections.addRecipe).toHaveBeenCalledWith(1, 42)
    })
