import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import TimerPanel from '../components/TimerPanel'
import type { UseTimersReturn, Timer } from '../hooks/useTimers'
import { api } from '../api/client'

// Mock the API
vi.mock('../api/client', () => ({
  api: {
    ai: {
      timerName: vi.fn(),
    },
  },
}))

const createMockTimer = (overrides: Partial<Timer> = {}): Timer => ({
  id: 'timer-1',
  label: 'Bake cookies',
  duration: 600,
  remaining: 300,
  isRunning: false,
  ...overrides,
})

const createMockTimersReturn = (timers: Timer[] = []): UseTimersReturn => ({
  timers,
  addTimer: vi.fn(),
  startTimer: vi.fn(),
  pauseTimer: vi.fn(),
  resetTimer: vi.fn(),
  deleteTimer: vi.fn(),
  toggleTimer: vi.fn(),
})

describe('TimerPanel', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('renders Timers header', () => {
    const mockTimers = createMockTimersReturn()
    render(<TimerPanel timers={mockTimers} />)
    expect(screen.getByText('Timers')).toBeInTheDocument()
  })

  it('shows timer count when timers exist', () => {
    const mockTimers = createMockTimersReturn([createMockTimer()])
    render(<TimerPanel timers={mockTimers} />)
    expect(screen.getByText('1')).toBeInTheDocument()
  })

  it('shows active timer count when timers are running', () => {
    const mockTimers = createMockTimersReturn([
      createMockTimer({ id: '1', isRunning: true }),
      createMockTimer({ id: '2', isRunning: false }),
    ])
    render(<TimerPanel timers={mockTimers} />)
    expect(screen.getByText(/1 active/)).toBeInTheDocument()
  })

  it('renders quick timer buttons', () => {
    const mockTimers = createMockTimersReturn()
    render(<TimerPanel timers={mockTimers} />)

    expect(screen.getByText('+5 min')).toBeInTheDocument()
    expect(screen.getByText('+10 min')).toBeInTheDocument()
    expect(screen.getByText('+15 min')).toBeInTheDocument()
  })

  it('adds timer when quick timer button is clicked (no AI)', async () => {
    const mockTimers = createMockTimersReturn()
    render(<TimerPanel timers={mockTimers} aiAvailable={false} />)

    fireEvent.click(screen.getByText('+5 min'))

    expect(mockTimers.addTimer).toHaveBeenCalledWith('5 min', 300)
  })

  it('uses AI to generate timer name when available', async () => {
    vi.mocked(api.ai.timerName).mockResolvedValue({ label: 'Browning onions' })

    const mockTimers = createMockTimersReturn()
    render(
      <TimerPanel
        timers={mockTimers}
        aiAvailable={true}
        instructionText="Sauté onions for 5 minutes"
      />
    )

    fireEvent.click(screen.getByText('+5 min'))

    await waitFor(() => {
      expect(api.ai.timerName).toHaveBeenCalledWith('Sauté onions for 5 minutes', 5)
      expect(mockTimers.addTimer).toHaveBeenCalledWith('Browning onions', 300)
    })
  })

  it('falls back to default label when AI fails', async () => {
    vi.mocked(api.ai.timerName).mockRejectedValue(new Error('API error'))

    const mockTimers = createMockTimersReturn()
    render(
      <TimerPanel
        timers={mockTimers}
        aiAvailable={true}
        instructionText="Sauté onions for 5 minutes"
      />
    )

    fireEvent.click(screen.getByText('+5 min'))

    await waitFor(() => {
      expect(mockTimers.addTimer).toHaveBeenCalledWith('5 min', 300)
    })
  })

  it('detects times in instruction text', () => {
    const mockTimers = createMockTimersReturn()
    render(
      <TimerPanel
        timers={mockTimers}
        instructionText="Bake for 20 minutes until golden"
      />
    )

    expect(screen.getByText('Detected in this step:')).toBeInTheDocument()
    expect(screen.getByText('20 min')).toBeInTheDocument()
  })

  it('detects multiple times in instruction text', () => {
    const mockTimers = createMockTimersReturn()
    render(
      <TimerPanel
        timers={mockTimers}
        instructionText="Preheat for 10 minutes, then bake for 30 minutes"
      />
    )

    expect(screen.getByText('10 min')).toBeInTheDocument()
    expect(screen.getByText('30 min')).toBeInTheDocument()
  })

  it('adds detected time when clicked', async () => {
    const mockTimers = createMockTimersReturn()
    render(
      <TimerPanel
        timers={mockTimers}
        aiAvailable={false}
        instructionText="Bake for 15 minutes"
      />
    )

    // Find the detected time button (not the quick timer)
    const detectedButtons = screen.getAllByText('15 min')
    // The detected time button should be in the "Detected in this step" section
    const detectedButton = detectedButtons.find(btn =>
      btn.closest('div')?.className.includes('bg-primary/10')
    )

    if (detectedButton) {
      fireEvent.click(detectedButton)
      expect(mockTimers.addTimer).toHaveBeenCalledWith('15 min', 900)
    }
  })

  it('displays existing timers', () => {
    const mockTimers = createMockTimersReturn([
      createMockTimer({ label: 'Bake cookies', remaining: 300 }),
    ])
    render(<TimerPanel timers={mockTimers} />)

    expect(screen.getByText('Bake cookies')).toBeInTheDocument()
  })

  it('shows empty message when no timers', () => {
    const mockTimers = createMockTimersReturn([])
    render(<TimerPanel timers={mockTimers} />)

    expect(screen.getByText('No active timers. Add one above!')).toBeInTheDocument()
  })

  it('can be collapsed', () => {
    const mockTimers = createMockTimersReturn()
    render(<TimerPanel timers={mockTimers} />)

    // Initially expanded - quick timer buttons should be visible
    expect(screen.getByText('+5 min')).toBeInTheDocument()

    // Click header to collapse
    fireEvent.click(screen.getByText('Timers'))

    // Quick timer buttons should be hidden
    expect(screen.queryByText('+5 min')).not.toBeInTheDocument()
  })

  it('shows AI sparkle icon when AI is available and has instruction text', () => {
    const mockTimers = createMockTimersReturn()
    const { container } = render(
      <TimerPanel
        timers={mockTimers}
        aiAvailable={true}
        instructionText="Some instruction"
      />
    )

    // Check for sparkles icon (Lucide icon)
    expect(container.querySelector('.lucide-sparkles')).toBeInTheDocument()
  })

  it('formats detected hour times correctly', () => {
    const mockTimers = createMockTimersReturn()
    render(
      <TimerPanel
        timers={mockTimers}
        instructionText="Let rise for 2 hours"
      />
    )

    expect(screen.getByText('2h')).toBeInTheDocument()
  })

  it('formats detected seconds correctly', () => {
    const mockTimers = createMockTimersReturn()
    render(
      <TimerPanel
        timers={mockTimers}
        instructionText="Microwave for 30 seconds"
      />
    )

    expect(screen.getByText('30s')).toBeInTheDocument()
  })
})

import { describe, it, expect, vi } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import TimerWidget from '../components/TimerWidget'
import type { Timer } from '../hooks/useTimers'

const createMockTimer = (overrides: Partial<Timer> = {}): Timer => ({
  id: 'timer-1',
  label: 'Bake cookies',
  duration: 600,
  remaining: 300,
  isRunning: false,
  ...overrides,
})

describe('TimerWidget', () => {
  it('renders timer label', () => {
    const timer = createMockTimer()
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    expect(screen.getByText('Bake cookies')).toBeInTheDocument()
  })

  it('displays remaining time in mm:ss format', () => {
    const timer = createMockTimer({ remaining: 300 })
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    expect(screen.getByText('5:00')).toBeInTheDocument()
  })

  it('displays remaining time in h:mm:ss format for long timers', () => {
    const timer = createMockTimer({ remaining: 3661 }) // 1 hour, 1 min, 1 sec
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    expect(screen.getByText('1:01:01')).toBeInTheDocument()
  })

  it('shows Play button when timer is not running', () => {
    const timer = createMockTimer({ isRunning: false })
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    expect(screen.getByLabelText('Play')).toBeInTheDocument()
  })

  it('shows Pause button when timer is running', () => {
    const timer = createMockTimer({ isRunning: true })
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    expect(screen.getByLabelText('Pause')).toBeInTheDocument()
  })

  it('calls onToggle when play/pause button is clicked', () => {
    const handleToggle = vi.fn()
    const timer = createMockTimer()
    render(
      <TimerWidget
        timer={timer}
        onToggle={handleToggle}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    fireEvent.click(screen.getByLabelText('Play'))
    expect(handleToggle).toHaveBeenCalled()
  })

  it('calls onReset when reset button is clicked', () => {
    const handleReset = vi.fn()
    const timer = createMockTimer()
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={handleReset}
        onDelete={vi.fn()}
      />
    )
    fireEvent.click(screen.getByLabelText('Reset'))
    expect(handleReset).toHaveBeenCalled()
  })

  it('calls onDelete when delete button is clicked', () => {
    const handleDelete = vi.fn()
    const timer = createMockTimer()
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={handleDelete}
      />
    )
    fireEvent.click(screen.getByLabelText('Delete'))
    expect(handleDelete).toHaveBeenCalled()
  })

  it('hides play/pause and reset buttons when timer is complete', () => {
    const timer = createMockTimer({ remaining: 0 })
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    expect(screen.queryByLabelText('Play')).not.toBeInTheDocument()
    expect(screen.queryByLabelText('Pause')).not.toBeInTheDocument()
    expect(screen.queryByLabelText('Reset')).not.toBeInTheDocument()
    // Delete button should still be visible
    expect(screen.getByLabelText('Delete')).toBeInTheDocument()
  })

  it('shows 0:00 when timer is complete', () => {
    const timer = createMockTimer({ remaining: 0 })
    render(
      <TimerWidget
        timer={timer}
        onToggle={vi.fn()}
        onReset={vi.fn()}
        onDelete={vi.fn()}
      />
    )
    expect(screen.getByText('0:00')).toBeInTheDocument()
  })
})

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { api } from '../api/client'

// Mock fetch globally
const mockFetch = vi.fn()
globalThis.fetch = mockFetch

describe('API Client', () => {
  beforeEach(() => {
    mockFetch.mockClear()
  })

  afterEach(() => {
    vi.resetAllMocks()
  })

  describe('profiles', () => {
    it('lists profiles', async () => {
      const profiles = [
        { id: 1, name: 'Alice', avatar_color: '#d97850', theme: 'light', unit_preference: 'us' },
        { id: 2, name: 'Bob', avatar_color: '#8fae6f', theme: 'dark', unit_preference: 'metric' },
      ]
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(profiles),
      })

      const result = await api.profiles.list()

      expect(mockFetch).toHaveBeenCalledWith('/api/profiles/', expect.objectContaining({
        headers: { 'Content-Type': 'application/json' },
      }))
      expect(result).toEqual(profiles)
    })

    it('creates a profile', async () => {
      const newProfile = { name: 'Charlie', avatar_color: '#6b9dad' }
      const createdProfile = { id: 3, ...newProfile, theme: 'light', unit_preference: 'us' }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(createdProfile),
      })

      const result = await api.profiles.create(newProfile)

      expect(mockFetch).toHaveBeenCalledWith('/api/profiles/', expect.objectContaining({
        method: 'POST',
        body: JSON.stringify(newProfile),
      }))
      expect(result).toEqual(createdProfile)
    })

    it('selects a profile', async () => {
      const profile = { id: 1, name: 'Alice', avatar_color: '#d97850', theme: 'light', unit_preference: 'us' }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(profile),
      })

      const result = await api.profiles.select(1)

      expect(mockFetch).toHaveBeenCalledWith('/api/profiles/1/select/', expect.objectContaining({
        method: 'POST',
      }))
      expect(result).toEqual(profile)
    })

    it('updates a profile', async () => {
      const updatedProfile = { id: 1, name: 'Alice', avatar_color: '#d97850', theme: 'dark', unit_preference: 'us' }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(updatedProfile),
      })

      const result = await api.profiles.update(1, { name: 'Alice', avatar_color: '#d97850', theme: 'dark' })

      expect(mockFetch).toHaveBeenCalledWith('/api/profiles/1/', expect.objectContaining({
        method: 'PUT',
      }))
      expect(result.theme).toBe('dark')
    })

    it('deletes a profile', async () => {
      mockFetch.mockResolvedValueOnce({
        ok: true,
        status: 204,
        json: () => Promise.resolve(null),
      })

      await api.profiles.delete(1)

      expect(mockFetch).toHaveBeenCalledWith('/api/profiles/1/', expect.objectContaining({
        method: 'DELETE',
      }))
    })
  })

  describe('search', () => {
    it('searches recipes with query', async () => {
      const searchResponse = {
        results: [
          { url: 'https://example.com/recipe1', title: 'Chocolate Cookies', host: 'example.com', image_url: '', description: 'Delicious cookies' },
          { url: 'https://example.com/recipe2', title: 'Sugar Cookies', host: 'example.com', image_url: '', description: 'Sweet treats' },
        ],
        total: 2,
        page: 1,
        has_more: false,
        sites: { 'example.com': 2 },
      }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(searchResponse),
      })

      const result = await api.recipes.search('cookies')

      expect(mockFetch).toHaveBeenCalledWith('/api/recipes/search/?q=cookies&page=1', expect.any(Object))
      expect(result.results).toHaveLength(2)
      expect(result.total).toBe(2)
      expect(result.has_more).toBe(false)
    })

    it('searches recipes with source filter', async () => {
      const searchResponse = {
        results: [{ url: 'https://allrecipes.com/recipe', title: 'Recipe', host: 'allrecipes.com', image_url: '', description: '' }],
        total: 1,
        page: 1,
        has_more: false,
        sites: { 'allrecipes.com': 1 },
      }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(searchResponse),
      })

      const result = await api.recipes.search('cookies', 'allrecipes.com')

      expect(mockFetch).toHaveBeenCalledWith('/api/recipes/search/?q=cookies&page=1&sources=allrecipes.com', expect.any(Object))
      expect(result.results).toHaveLength(1)
    })

    it('searches recipes with pagination', async () => {
      const searchResponse = {
        results: [],
        total: 20,
        page: 3,
        has_more: false,
        sites: {},
      }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(searchResponse),
      })

      const result = await api.recipes.search('cookies', undefined, 3)

      expect(mockFetch).toHaveBeenCalledWith('/api/recipes/search/?q=cookies&page=3', expect.any(Object))
      expect(result.page).toBe(3)
    })

    it('returns has_more when more results exist', async () => {
      const searchResponse = {
        results: Array(6).fill({ url: '', title: '', host: '', image_url: '', description: '' }),
        total: 50,
        page: 1,
        has_more: true,
        sites: {},
      }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(searchResponse),
      })

      const result = await api.recipes.search('pasta')

      expect(result.has_more).toBe(true)
      expect(result.total).toBe(50)
    })
  })

  describe('scrape', () => {
    it('scrapes a recipe from URL', async () => {
      const recipe = {
        id: 1,
        title: 'Chocolate Cake',
        host: 'example.com',
        image_url: 'https://example.com/cake.jpg',
        image: null,
        total_time: 60,
        rating: 4.5,
        is_remix: false,
        scraped_at: '2024-01-01T00:00:00Z',
      }
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(recipe),
      })

      const result = await api.recipes.scrape('https://example.com/chocolate-cake')

      expect(mockFetch).toHaveBeenCalledWith('/api/recipes/scrape/', expect.objectContaining({
        method: 'POST',
        body: JSON.stringify({ url: 'https://example.com/chocolate-cake' }),
      }))
      expect(result.title).toBe('Chocolate Cake')
    })
  })

  describe('recipes.list', () => {
    const mockRecipe = {
      id: 1,
      title: 'My Recipe',
      host: 'example.com',
      image_url: 'https://example.com/img.jpg',
      image: null,
      total_time: 30,
      rating: 4.5,
      is_remix: false,
      scraped_at: '2024-01-01T00:00:00Z',
    }

    it('lists all recipes', async () => {
      const recipes = [mockRecipe]
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(recipes),
      })

      const result = await api.recipes.list()

      expect(mockFetch).toHaveBeenCalledWith('/api/recipes/?limit=50&offset=0', expect.any(Object))
      expect(result).toHaveLength(1)
      expect(result[0].title).toBe('My Recipe')
    })

    it('lists recipes with custom limit', async () => {
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve([]),
      })

      await api.recipes.list(100)

      expect(mockFetch).toHaveBeenCalledWith('/api/recipes/?limit=100&offset=0', expect.any(Object))
    })

    it('lists recipes with offset', async () => {
      mockFetch.mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve([]),
      })

      await api.recipes.list(50, 10)

      expect(mockFetch).toHaveBeenCalledWith('/api/recipes/?limit=50&offset=10', expect.any(Object))
    })
  })

  describe('collections', () => {
    const mockRecipe = {
      id: 1,
      title: 'Test Recipe',
      host: 'example.com',
      image_url: 'https://example.com/img.jpg',
      image: null,
      total_time: 30,
      rating: 4.5,
      is_remix: false,
      scraped_at: '2024-01-01T00:00:00Z',
    }

    it('lists collections', async () => {
      const collections = [
        { id: 1, name: 'Weeknight Dinners', description: 'Quick meals', recipe_count: 5, created_at: '2024-01-01T00:00:00Z', updated_at: '2024-01-01T00:00:00Z' },
        { id: 2, name: 'Holiday Baking', description: '', recipe_count: 3, created_at: '2024-01-02T00:00:00Z', updated_at: '2024-01-02T00:00:00Z' },
      ]
      mockFetch.mockResolvedValueOnce({
        ok: true,
